// ── HISTORY — 7-day play history in album-art grid ───────────────────────────

async function viewHistory() {
  setTitle(t('player.title.history')); setBack(null); setNavActive('history'); S.view = 'history';
  setBody('<div class="loading-state"></div>');
  try {
    const d = await api('GET', 'api/v1/history');
    if (!d.events?.length) {
      setBody(`<div class="empty-state">${t('player.history.noHistory')}</div>`);
      return;
    }

    // ── Helpers ──────────────────────────────────────────────────────────────
    const _dayKey = ms => {
      const dt = new Date(ms);
      return `${dt.getFullYear()}-${String(dt.getMonth()+1).padStart(2,'0')}-${String(dt.getDate()).padStart(2,'0')}`;
    };
    const _hour = ms => new Date(ms).getHours();
    const _timeStr = ms => {
      const dt = new Date(ms);
      return `${String(dt.getHours()).padStart(2,'0')}:${String(dt.getMinutes()).padStart(2,'0')}`;
    };
    const _dayLabel = key => {
      const [y, mo, d2] = key.split('-').map(Number);
      const now = new Date();
      if (key === _dayKey(now.getTime()))           return t('player.history.today');
      if (key === _dayKey(now.getTime() - 86400000)) return t('player.history.yesterday');
      return new Date(y, mo - 1, d2).toLocaleDateString(I18N.getLanguage(), { weekday: 'long' });
    };
    const _dayLabelLong = key => {
      const [y, mo, d2] = key.split('-').map(Number);
      return new Date(y, mo - 1, d2).toLocaleDateString(I18N.getLanguage(), { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
    };

    // ── Group by day ─────────────────────────────────────────────────────────
    function _buildDays(events) {
      const dayMap = new Map();
      for (const e of events) {
        const key = _dayKey(e.started_at);
        if (!dayMap.has(key)) dayMap.set(key, []);
        dayMap.get(key).push(e);
      }
      return [...dayMap.entries()]
        .map(([key, dayEvents]) => ({
          key,
          label: _dayLabel(key),
          longLabel: _dayLabelLong(key),
          events: dayEvents.toSorted((a, b) => b.started_at - a.started_at)
        }))
        .toSorted((a, b) => b.key.localeCompare(a.key));
    }

    const days = _buildDays(d.events);

    S.curSongs = [];

    const body = document.getElementById('content-body');
    body.innerHTML = `
      <div class="fe-filter-row recent-view-bar" style="align-items:center;flex-wrap:nowrap;gap:8px;">
        <div class="recent-day-pills" id="hist-day-pills" style="display:flex;flex-wrap:nowrap;gap:8px;overflow-x:auto;white-space:nowrap;max-width:100%;flex:1 1 auto;min-width:0;"></div>
        <div class="hist-date-controls" style="display:flex;align-items:center;gap:8px;flex:0 0 auto;">
          <input type="date" id="hist-date-input" class="btn-sm" title="${t('player.nav.history')}" data-i18n="player.nav.history" data-i18n-attr="title" style="min-height:32px;">
          <button id="hist-date-reset" class="btn-sm hidden">&#8634;</button>
        </div>
        <div class="allib-view-controls" style="margin-left:0;flex:0 0 auto;">
          <button class="allib-density-btn" data-density="comfy"   title="${t('player.albums.densityComfy')}"><svg width="13" height="13" viewBox="0 0 14 14" fill="currentColor"><rect x="0" y="0" width="6" height="6" rx="1"/><rect x="8" y="0" width="6" height="6" rx="1"/><rect x="0" y="8" width="6" height="6" rx="1"/><rect x="8" y="8" width="6" height="6" rx="1"/></svg></button>
          <button class="allib-density-btn" data-density="compact" title="${t('player.albums.densityCompact')}"><svg width="13" height="13" viewBox="0 0 14 14" fill="currentColor"><rect x="0" y="0" width="4" height="4" rx=".5"/><rect x="5" y="0" width="4" height="4" rx=".5"/><rect x="10" y="0" width="4" height="4" rx=".5"/><rect x="0" y="5" width="4" height="4" rx=".5"/><rect x="5" y="5" width="4" height="4" rx=".5"/><rect x="10" y="5" width="4" height="4" rx=".5"/><rect x="0" y="10" width="4" height="4" rx=".5"/><rect x="5" y="10" width="4" height="4" rx=".5"/><rect x="10" y="10" width="4" height="4" rx=".5"/></svg></button>
          <button class="allib-density-btn" data-density="list"    title="${t('player.albums.densityList')}"><svg width="13" height="13" viewBox="0 0 14 14" fill="currentColor"><rect x="0" y="1" width="14" height="2" rx="1"/><rect x="0" y="6" width="14" height="2" rx="1"/><rect x="0" y="11" width="14" height="2" rx="1"/></svg></button>
        </div>
      </div>
      <div class="hist-hour-row hidden"></div>
      <div class="hist-view-content"></div>`;

    const _densityKey = 'ms2_history_density_' + (S.username || ''); // gitleaks:allow
    let curDensity = localStorage.getItem(_densityKey) || 'comfy';
    let selectedDateKey = days[0]?.key || _dayKey(Date.now());
    let calendarOverride = false;
    let curHour   = null; // null = show all hours
    let calendarDay = null;

    const dayPillsEl = body.querySelector('#hist-day-pills');
    const dateInputEl = body.querySelector('#hist-date-input');
    const dateResetEl = body.querySelector('#hist-date-reset');

    function _findDay(key) {
      const fromDays = days.find(d2 => d2.key === key);
      if (fromDays) return fromDays;
      if (calendarDay && calendarDay.key === key) return calendarDay;
      return {
        key,
        label: _dayLabel(key),
        longLabel: _dayLabelLong(key),
        events: []
      };
    }

    function _currentEvents() {
      return _findDay(selectedDateKey).events;
    }

    function renderDayPills() {
      if (calendarOverride) {
        const day = _findDay(selectedDateKey);
        dayPillsEl.innerHTML = `<button class="recent-day-pill active" data-day-key="${selectedDateKey}">
          ${esc(day.longLabel)} <span class="hist-pill-count">${day.events.length}</span>
        </button>`;
      } else {
        dayPillsEl.innerHTML = days.map(day => `<button class="recent-day-pill${day.key === selectedDateKey ? ' active' : ''}" data-day-key="${day.key}">
          ${esc(day.label)} <span class="hist-pill-count">${day.events.length}</span>
        </button>`).join('');
      }
      dayPillsEl.querySelectorAll('.recent-day-pill').forEach(pill => {
        pill.addEventListener('click', () => {
          calendarOverride = false;
          calendarDay = null;
          selectedDateKey = pill.dataset.dayKey;
          curHour = null;
          renderDayPills();
          renderDateControls();
          renderHourPills();
          renderGrid();
          body.scrollTop = 0;
        });
      });
    }

    function renderDateControls() {
      dateInputEl.value = selectedDateKey;
      dateResetEl.classList.toggle('hidden', !calendarOverride);
    }

    function _upsertCalendarDay(key, events) {
      const idx = days.findIndex(d2 => d2.key === key);
      const day = {
        key,
        label: _dayLabel(key),
        longLabel: _dayLabelLong(key),
        events: events.toSorted((a, b) => b.started_at - a.started_at)
      };
      if (idx >= 0) days[idx] = day;
      else calendarDay = day;
      if (idx >= 0) days.sort((a, b) => b.key.localeCompare(a.key));
    }

    async function _loadDayFromApi(dayKey) {
      const [y, mo, d2] = dayKey.split('-').map(Number);
      const fromMs = new Date(y, mo - 1, d2, 0, 0, 0, 0).getTime();
      const toMs = new Date(y, mo - 1, d2 + 1, 0, 0, 0, 0).getTime();
      const fresh = await api('GET', `api/v1/history?fromMs=${fromMs}&toMs=${toMs}`);
      const events = Array.isArray(fresh?.events) ? fresh.events : [];
      _upsertCalendarDay(dayKey, events);
      for (const e of events) _knownIds.add(e.id);
    }

    dateInputEl.addEventListener('change', async () => {
      if (!dateInputEl.value) return;
      calendarOverride = true;
      selectedDateKey = dateInputEl.value;
      curHour = null;
      try {
        await _loadDayFromApi(selectedDateKey);
      } catch { /* ignore fetch failures; keep current in-memory state */ }
      renderDayPills();
      renderDateControls();
      renderHourPills();
      renderGrid();
      body.scrollTop = 0;
    });

    dateResetEl.addEventListener('click', () => {
      calendarOverride = false;
      calendarDay = null;
      selectedDateKey = days[0]?.key || _dayKey(Date.now());
      curHour = null;
      renderDayPills();
      renderDateControls();
      renderHourPills();
      renderGrid();
      body.scrollTop = 0;
    });

    const _eventToSong = e => ({
      filepath:    e.filepath,
      title:       e.title,
      artist:      e.artist,
      album:       e.album,
      'album-art': e.aaFile,
    });

    // ── Render the hour pills for a given day ─────────────────────────────────
    function renderHourPills() {
      const hourRow = body.querySelector('.hist-hour-row');
      const events  = _currentEvents();

      // Build hour -> count map (latest hour first)
      const hourCounts = new Map();
      for (const e of events) {
        const h = _hour(e.started_at);
        hourCounts.set(h, (hourCounts.get(h) ?? 0) + 1);
      }
      const hours = [...hourCounts.keys()].toSorted((a, b) => b - a);

      if (hours.length === 0) { hourRow.classList.add('hidden'); hourRow.innerHTML = ''; return; }
      if (curHour !== null && !hourCounts.has(curHour)) curHour = null;

      hourRow.classList.remove('hidden');
      hourRow.innerHTML = `
        <div class="hist-hour-pills">
          <button class="hist-hour-pill${curHour === null ? ' active' : ''}" data-hour="all">
            ${t('player.history.hourAll')} <span class="hist-pill-count">${events.length}</span>
          </button>
          ${hours.map(h => `<button class="hist-hour-pill${curHour === h ? ' active' : ''}" data-hour="${h}">
            ${String(h).padStart(2,'0')}:00 <span class="hist-pill-count">${hourCounts.get(h)}</span>
          </button>`).join('')}
        </div>`;

      hourRow.querySelectorAll('.hist-hour-pill').forEach(pill => {
        pill.addEventListener('click', () => {
          hourRow.querySelectorAll('.hist-hour-pill').forEach(p => p.classList.remove('active'));
          pill.classList.add('active');
          curHour = pill.dataset.hour === 'all' ? null : Number.parseInt(pill.dataset.hour, 10);
          renderGrid();
          body.scrollTop = 0;
        });
      });
    }

    // ── Render the card grid for current day + hour filter ────────────────────
    function renderGrid() {
      const allEvents = _currentEvents();
      const events    = curHour === null ? allEvents : allEvents.filter(e => _hour(e.started_at) === curHour);
      const songs     = events.map(_eventToSong);

      S.curSongs = songs;
      document.getElementById('play-all-btn').onclick = () => {
        if (songs.length) { _setPlaySource(null); Player.setQueue(songs, 0); toast(t('player.toast.playingSongs', { count: songs.length })); }
      };
      document.getElementById('add-all-btn').onclick  = () => { if (songs.length) Player.addAll(songs); };

      const wrap      = body.querySelector('.hist-view-content');
      const gridClass = 'album-grid' + (curDensity === 'compact' ? ' album-grid--compact' : curDensity === 'list' ? ' album-grid--list' : '');

      if (!events.length) {
        wrap.innerHTML = `<div class="empty-state">${t('player.history.noHistory')}</div>`;
        return;
      }

      const cards = events.map((e, i) => {
        const art   = artUrl(e.aaFile, 'l');
        const time  = _timeStr(e.started_at);
        const title = esc(e.title  || t('player.history.unknownTitle'));
        const sub   = esc(e.artist || t('player.history.unknownArtist'));
        if (curDensity === 'list') {
          return `<div class="album-card" data-hist-i="${i}" style="display:flex;align-items:center;gap:10px;padding:6px 8px;min-height:56px;">
            <div class="album-art" style="width:44px;min-width:44px;height:44px;border-radius:8px;overflow:hidden;">
              ${art ? `<img src="${art}" alt="" loading="lazy" onerror="this.style.display='none'">` : `<div class="no-art no-art-album"><div class="no-art-wave"><span></span><span></span><span></span><span></span><span></span></div></div>`}
              <div class="play-ov" style="inset:0;"><svg width="18" height="18" viewBox="0 0 24 24" fill="white"><polygon points="5,3 19,12 5,21"/></svg></div>
            </div>
            <div class="album-meta" style="min-width:0;flex:1 1 auto;">
              <div class="album-name" style="white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${title}</div>
              <div class="album-year" style="white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${sub}</div>
            </div>
            <div class="album-year" style="margin-left:auto;white-space:nowrap;font-weight:700;">${time}</div>
          </div>`;
        }
        return `<div class="album-card" data-hist-i="${i}">
          <div class="album-art">
            ${art ? `<img src="${art}" alt="" loading="lazy" onerror="this.style.display='none'">` : `<div class="no-art no-art-album"><div class="no-art-wave"><span></span><span></span><span></span><span></span><span></span></div><span class="no-art-label">no artwork</span></div>`}
            <div class="play-ov"><svg width="30" height="30" viewBox="0 0 24 24" fill="white"><polygon points="5,3 19,12 5,21"/></svg></div>
          </div>
          <div class="album-meta">
            <div class="album-name">${title}</div>
            <div class="album-year">${sub} · <span class="hist-time">${time}</span></div>
          </div>
        </div>`;
      });

      wrap.innerHTML = `<div class="${gridClass}">${cards.join('')}</div>`;

      wrap.querySelectorAll('.album-card').forEach(card => {
        card.addEventListener('click', () => {
          const idx = Number.parseInt(card.dataset.histI, 10);
          Player.addSong(songs[idx]);
          toast(t('player.toast.added', { title: songs[idx].title || songs[idx].filepath?.split('/').pop() || '?' }));
        });
      });
    }

    function applyDensity(d2) {
      curDensity = d2;
      localStorage.setItem(_densityKey, d2);
      body.querySelectorAll('.allib-density-btn').forEach(b => b.classList.toggle('active', b.dataset.density === d2));
      renderGrid();
    }

    body.querySelectorAll('.allib-density-btn').forEach(b => b.addEventListener('click', () => applyDensity(b.dataset.density)));

    // Initial render
    body.querySelectorAll('.allib-density-btn').forEach(b => b.classList.toggle('active', b.dataset.density === curDensity));
    renderDayPills();
    renderDateControls();
    renderHourPills();
    renderGrid();

    // ── Live refresh when a new song starts ─────────────────────────────────
    // Re-fetches history silently and prepends any new event that appeared since
    // the last fetch (i.e. the song that just started). Preserves the current
    // day/hour selection; only re-renders if today (index 0) is active.
    const _knownIds = new Set(days.flatMap(d => d.events.map(e => e.id)));
    _historyRefreshFn = async () => {
      try {
        const fresh = await api('GET', 'api/v1/history');
        if (!fresh.events?.length) return;

        // Find events we haven't seen yet
        const newEvents = fresh.events.filter(e => !_knownIds.has(e.id));
        if (!newEvents.length) return;
        for (const e of newEvents) _knownIds.add(e.id);

        // Rebuild days from fresh data (order may change)
        const freshDays = _buildDays(fresh.events);

        // Update days array in-place
        days.length = 0;
        for (const fd of freshDays) days.push(fd);

        renderDayPills();
        renderDateControls();
        renderHourPills();
        renderGrid();
      } catch { /* silent — live refresh is best-effort */ }
    };

  } catch(e) { setBody(`<div class="empty-state">${t('player.search.failed', { error: esc(e.message) })}</div>`); }
}

// ── HOME ─────────────────────────────────────────────────────

// Launches the user's pinned start view, or falls back to Home if none is set.
function _launchPinnedViewOrHome() {
  const v = S.pinnedView;
  if (v === 'playing-now')  { viewPlayingNow(); return; }
  if (v === 'history')      { viewHistory(); return; }
  if (v === 'shortcuts')    { viewShortcuts(); return; }
  if (v === 'search')       { viewSearch(); return; }
  if (v === 'files')        { S.feDirStack = []; S.feFilter = ''; viewFiles('', false); return; }
  if (v === 'recent')       { viewRecent(); return; }
  if (v === 'artists')      { viewArtists(); return; }
  if (v === 'artists_old')  { viewArtists_old(); return; }
  if (v === 'album-library') { viewAlbumLibrary(); return; }
  if (v === 'genres')       { viewGenres(); return; }
  if (v === 'decades')      { viewDecades(); return; }
  if (v === 'autodj')       { viewAutoDJ(); return; }
  if (v === 'playback')     { viewPlayback(); return; }
  viewHome(); // default — 'home' or no pin set
}

// ── PLAYING NOW VIEW ──────────────────────────────────────────────────────────
// Full-page "Spotify-style" view for the currently playing track:
//   hero (big art + title + artist), metadata table, artist bio (Last.fm),
//   albums from library, similar artists.
let _pnowSongFp        = null;  // filepath of song currently rendered in view
let _pnowArtist        = null;  // artist string currently rendered
let _pnowViewActive    = false; // true while this view is shown
let _pnowLastCueArtist = '';    // last CUE chapter artist shown in pnow — avoids redundant re-fetches

async function viewPlayingNow() {
  setTitle(t('player.nav.playingNow'));
  setBack(null);
  setNavActive('playing-now');
  S.view = 'playing-now';
  _pnowViewActive = true;
  await _renderPlayingNow();
}

async function _renderPlayingNow(fade) {
  if (S.view !== 'playing-now') return;
  const body = document.getElementById('content-body');
  if (!body) return;

  const s = S.queue[S.idx] || null;

  // ── Nothing playing ──────────────────────────────────────────────────────
  if (!s || s.isRadio) {
    _pnowSongFp = null;
    _pnowArtist = null;
    body.innerHTML = `<div class="pnow-view pnow-visible">
      <div class="pnow-empty">
        <svg width="56" height="56" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">
          <circle cx="12" cy="12" r="10"/>
          <polygon points="10,8 16,12 10,16"/>
        </svg>
        <p>${t('player.pnow.noSong')}</p>
      </div>
    </div>`;
    return;
  }

  // ── Fade out if already showing different content ────────────────────────
  const existing = body.querySelector('.pnow-view');
  if (fade && existing) {
    existing.classList.add('pnow-fading');
    existing.classList.remove('pnow-visible');
    await new Promise(r => setTimeout(r, 260));
    if (S.view !== 'playing-now') return;
  }

  _pnowSongFp = s.filepath;
  _pnowArtist = s.artist || null;
  _pnowLastCueArtist = ''; // reset so first CUE chapter fetch always fires

  const artU = artUrl(s['album-art'], 'l');
  const artHtml = artU
    ? `<img src="${artU}" alt="" onerror="this.parentNode.innerHTML=noArtHtml()">`
    : noArtHtml();

  const stars = Array.from({length:5}, (_, i) => {
    const lit = i < Math.round((s.rating || 0) / 2);
    return `<span class="star${lit ? ' lit' : ''}">★</span>`;
  }).join('');

  const artistLine = s.artist ? `<div class="pnow-artist">${esc(s.artist)}</div>` : '';
  const albumLine  = [s.album, s.year].filter(Boolean).join(' · ');

  // Tech pills: format, bitrate, sample-rate
  const ext = (s.filepath || '').split('.').pop().toUpperCase();
  const pills = [
    ext ? `<span class="pnow-pill pnow-pill--gray">${esc(ext)}</span>` : '',
    s.bitrate  ? `<span class="pnow-pill pnow-pill--gray">${s.bitrate} kbps</span>` : '',
    s['sample-rate'] ? `<span class="pnow-pill pnow-pill--gray">${(s['sample-rate']/1000).toFixed(1)} kHz</span>` : '',
    s.bpm ? `<span class="pnow-pill pnow-pill--gray">${s.bpm} BPM</span>` : '',
    s.musical_key ? `<span class="pnow-pill pnow-pill--gray">${esc(s.musical_key)}${toCamelot(s.musical_key) ? ' (' + toCamelot(s.musical_key) + ')' : ''}</span>` : '',
    s.genre    ? `<span class="pnow-pill">${esc(s.genre)}</span>` : '',
  ].filter(Boolean).join('');

  // Metadata table rows
  function mv(v) { return v != null ? `<span class="pnow-meta-v">${esc(String(v))}</span>` : `<span class="pnow-meta-v dim">—</span>`; }
  const rgStr = s.replaygain != null ? `${s.replaygain > 0 ? '+' : ''}${Number(s.replaygain).toFixed(2)} dB` : null;
  const metaRows = [
    [t('metadata.title'),  s.title],
    [t('metadata.artist'), s.artist],
    [t('metadata.album'),  s.album],
    [t('metadata.year'),   s.year],
    [t('metadata.track'),  s.track],
    [t('metadata.disc'),   s.disk],
    [t('metadata.replayGain'), rgStr],
  ].map(([k, v]) => `<span class="pnow-meta-k">${esc(k||'')}:</span>${mv(v)}`).join('');

  body.innerHTML = `<div class="pnow-view pnow-fading">
    <div class="pnow-hero">
      <div class="pnow-hero-bg" id="pnow-bg" ${artU ? `style="background-image:url(${artU})"` : ''}></div>
      <div class="pnow-art">${artHtml}</div>
      <div class="pnow-hero-info">
        <div class="pnow-label">${t('player.pnow.nowPlaying')}</div>
        <div class="pnow-title">${esc(s.title || s.filepath?.split('/').pop() || '—')}</div>
        ${artistLine}
        ${albumLine ? `<div class="pnow-album">${esc(albumLine)}</div>` : ''}
        <div class="pnow-stars">${stars}</div>
      </div>
    </div>
    ${pills ? `<div class="pnow-pills">${pills}</div>` : ''}
    <div class="pnow-body">
      <div class="pnow-main">
        <div class="pnow-section-title" id="pnow-bio-title"></div>
        <div class="pnow-bio" id="pnow-bio"></div>
        <button class="pnow-bio-more hidden" id="pnow-bio-more">${t('player.pnow.readMore')}</button>
        <div class="pnow-section-title" id="pnow-sim-title"></div>
        <div class="pnow-sim-list" id="pnow-sim"></div>
        <div class="pnow-section-title" id="pnow-albums-title"></div>
        <div class="pnow-albums" id="pnow-albums"></div>
      </div>
      <div class="pnow-sidebar">
        <div id="pnow-artist-img-wrap"></div>
        <div class="pnow-section-title">${t('player.pnow.trackInfo')}</div>
        <div class="pnow-meta-grid">${metaRows}</div>
      </div>
    </div>
  </div>`;

  // Fade in
  requestAnimationFrame(() => {
    const el = body.querySelector('.pnow-view');
    if (el) { el.classList.remove('pnow-fading'); el.classList.add('pnow-visible'); }
  });

  // Async: load artist bio + similar artists + library albums in parallel
  _pnowLoadArtistData(s.artist, s.filepath);
}

// Collapse collaboration variants into one chip per base artist.
// "Blank & Jones ft. Robert Smith" and "Blank & Jones feat. Bernard Sumner" both
// reduce to base "Blank & Jones" — only one entry is kept (the canonical form if
// it appears in the list, otherwise the first encountered variant).
function _deduplicateSimArtists(artists) {
  const COLLAB_RE = /\s+(?:ft\.?|feat(?:uring)?\.?|vs\.?|with|pres(?:ents)?\.?|\u00d7)\s+.*/i;
  const seen = new Map(); // baseLower → { bestName, isExact }
  for (const name of artists) {
    const base     = name.replace(COLLAB_RE, '').trim();
    const baseLower = base.toLowerCase();
    const isExact  = name.trim().toLowerCase() === baseLower;
    if (!seen.has(baseLower)) {
      seen.set(baseLower, { bestName: name, isExact });
    } else if (isExact && !seen.get(baseLower).isExact) {
      // Upgrade to the canonical form when we find the exact base name
      seen.set(baseLower, { bestName: name, isExact: true });
    }
  }
  return [...seen.values()].map(v => v.bestName);
}

// Extract the primary artist from a feat./ft./with/vs. tag, e.g.
// "Calvin Harris feat. Ellie Goulding" → "Calvin Harris"
const _FEAT_RE = /\s*[([{]?\s*(?:ft\.?|feat(?:uring)?\.?|vs\.?|with|pres(?:ents)?\.?|\u00d7)\s+.*/i;
function _primaryArtist(name) {
  if (!name) return name;
  return name.replace(_FEAT_RE, '').trim() || name;
}

async function _pnowLoadArtistData(artist, forFp, skipImg = false) {
  if (S.view !== 'playing-now' || _pnowSongFp !== forFp) return;

  // Strip feat./ft./with/vs. — primary artist for guard/fallback
  const primaryArtist = _primaryArtist(artist);

  const bioEl      = document.getElementById('pnow-bio');
  const bioTitle   = document.getElementById('pnow-bio-title');
  const bioMore    = document.getElementById('pnow-bio-more');
  const simEl      = document.getElementById('pnow-sim');
  const simTitle   = document.getElementById('pnow-sim-title');
  const albumsEl   = document.getElementById('pnow-albums');
  const albumsTitle= document.getElementById('pnow-albums-title');
  if (!bioEl || !albumsEl) return;

  // ── 0. Artist image from local cache (TheAudioDB/Discogs/Last.fm, stored server-side) ─
  // For CUE-sheet VA albums, use the current chapter artist instead of the file-level artist.
  const imgArtist = (() => {
    if (_cuePoints.length && audioEl.duration) {
      const pos = audioEl.currentTime;
      const passed = _cuePoints.filter(cp => cp.t <= pos);
      const cur = passed[passed.length - 1] || null;
      const chTitle = cur?.title || _cueTrack1Title || '';
      const sep = chTitle.indexOf(' - ');
      if (sep > 0) {
        const a = chTitle.slice(0, sep).trim();
        _pnowLastCueArtist = a; // prevent duplicate fetch on next timeupdate
        return a;
      }
    }
    return artist;
  })();
  // For VA CUE files the chapter gives the real artist (e.g. 'Cerrone'), while
  // the file-level tag is 'Various Artists'. Use the chapter artist everywhere.
  const libArtist = _primaryArtist(imgArtist) || primaryArtist;
  if (!skipImg && imgArtist) {
    const wrap = document.getElementById('pnow-artist-img-wrap');
    const _pnowAlbumArt = artUrl(S.queue[S.idx]?.['album-art'], 's');
    if (wrap && _pnowAlbumArt) wrap.innerHTML = `<img class="pnow-tadb-img" src="${_pnowAlbumArt}" alt="" loading="lazy">`;
    api('GET', `api/v1/artists/image?artist=${encodeURIComponent(imgArtist)}`)
      .then(d => {
        if (_pnowSongFp !== forFp) return;
        const wrap2 = document.getElementById('pnow-artist-img-wrap');
        if (!wrap2) return;
        const finalSrc = d?.imageFile
          ? `api/v1/artists/images/${encodeURIComponent(d.imageFile)}`
          : artUrl(S.queue[S.idx]?.['album-art'], 's');
        if (finalSrc) {
          wrap2.innerHTML = `<img class="pnow-tadb-img" src="${finalSrc}" alt="" loading="lazy" onerror="this.parentNode.style.display='none'">`;
        }
      })
      .catch(() => {});
  }

  // ── 1. "In your Library" — Songs + Albums tabs (same as Artist page) ────
  if (libArtist) {
    const artistsArg = [libArtist];
    if (albumsTitle) albumsTitle.textContent = t('player.pnow.inYourLibrary') + ' — ' + libArtist;
    if (albumsEl) {
      albumsEl.style.display = 'block'; // override .pnow-albums grid — tabs need full width
      albumsEl.innerHTML = `
        <div class="artpro2-tab-bar" id="pnow-lib-tabs">
          <button class="artpro2-tab active" data-tab="songs">Songs</button>
          <button class="artpro2-tab" data-tab="albums">Albums</button>
        </div>
        <div class="artpro2-panel" id="pnow-lib-songs-panel">
          <div id="pnow-lib-songs"><div class="loading-state" style="height:80px;padding:16px 0"></div></div>
        </div>
        <div class="artpro2-panel hidden" id="pnow-lib-albums-panel">
          <div class="pnow-albums" id="pnow-lib-albums"><div class="loading-state" style="height:80px;padding:16px 0"></div></div>
        </div>`;

      albumsEl.querySelectorAll('.artpro2-tab').forEach(tab => {
        tab.addEventListener('click', () => {
          albumsEl.querySelectorAll('.artpro2-tab').forEach(t => t.classList.remove('active'));
          tab.classList.add('active');
          const which = tab.dataset.tab;
          albumsEl.querySelector('#pnow-lib-songs-panel').classList.toggle('hidden', which !== 'songs');
          albumsEl.querySelector('#pnow-lib-albums-panel').classList.toggle('hidden', which !== 'albums');
        });
      });
    }

    // Load songs + album library in parallel.
    // NOTE: do NOT apply _songsOnlyFilter() here — in the Now Playing context we
    // want to show ALL songs by this artist, including those in albumsOnly paths
    // (e.g. a track from the Disco vpath would otherwise be invisible even though
    // it is actively playing).
    const [songsRes, albRes] = await Promise.allSettled([
      api('POST', 'api/v1/db/artist-folder-songs', {
        artists: artistsArg,
      }),
      _loadAlbLib(),
    ]);
    if (_pnowSongFp !== forFp || S.view !== 'playing-now') return;

    const goBack = () => viewPlayingNow();

    // ── Songs panel ──────────────────────────────────────────────────────
    const songsEl2 = document.getElementById('pnow-lib-songs');
    const rawSongs = (songsRes.status === 'fulfilled' ? (songsRes.value || []) : []).map(s => norm(s));
    if (rawSongs.length && songsEl2) {
      const grouped = new Map();
      for (const s of rawSongs) {
        const folder = _songContainerFolder(s.filepath);
        if (!grouped.has(folder)) grouped.set(folder, []);
        grouped.get(folder).push(s);
      }
      let songsHtml = `<div style="margin-bottom:10px">
        <button class="artpro2-play-all-btn" id="pnow-lib-songs-play-all">▶ Play all (${rawSongs.length})</button>
      </div>`;
      for (const [folder, songs] of grouped) {
        const folderLabel = folder.split('/').pop() || folder;
        songsHtml += `<div class="artpro2-folder-group">
          <div class="artpro2-folder-header" data-folder>
            <span class="artpro2-folder-chevron">▶</span>${esc(folderLabel)}
            <span style="margin-left:auto;font-size:11px;font-weight:400;color:var(--t3)">(${songs.length})</span>
          </div>
          <div class="artpro2-folder-songs collapsed">`;
        for (const s of songs) {
          const dur = s.duration ? _fmtDuration(s.duration) : '';
          const title = s.title || s.filepath.split('/').pop();
          const trackNum = s.track ? `<span class="artpro2-track-num">${s.track}</span>` : '';
          songsHtml += `<div class="artpro2-song-row" data-fp="${esc(s.filepath)}">
            ${trackNum}
            <span class="artpro2-song-title">${esc(title)}</span>
            ${dur ? `<span class="artpro2-song-dur">${dur}</span>` : ''}
            <button class="artpro2-song-add" data-fp="${esc(s.filepath)}" title="Add to queue">+</button>
          </div>`;
        }
        songsHtml += `</div></div>`;
      }
      songsEl2.innerHTML = songsHtml;
      songsEl2.querySelector('#pnow-lib-songs-play-all')?.addEventListener('click', () => Player.setQueue(rawSongs, 0));
      songsEl2.querySelectorAll('[data-folder]').forEach(header => {
        header.addEventListener('click', () => {
          const div = header.nextElementSibling;
          const collapsed = div.classList.toggle('collapsed');
          header.classList.toggle('open', !collapsed);
        });
      });
      songsEl2.querySelectorAll('.artpro2-song-row').forEach(row => {
        row.addEventListener('click', e => {
          if (e.target.closest('.artpro2-song-add')) return;
          const s = rawSongs.find(x => x.filepath === row.dataset.fp);
          if (s) Player.addSong(s);
        });
      });
      songsEl2.querySelectorAll('.artpro2-song-add').forEach(btn => {
        btn.addEventListener('click', e => {
          e.stopPropagation();
          const s = rawSongs.find(x => x.filepath === btn.dataset.fp);
          if (s) Player.addSong(s);
        });
      });
      const songsTabBtn = albumsEl?.querySelector('.artpro2-tab[data-tab="songs"]');
      if (songsTabBtn && rawSongs.length) songsTabBtn.textContent = `Songs (${rawSongs.length})`;
    } else if (songsEl2) {
      songsEl2.innerHTML = `<p style="color:var(--t3);font-size:13px;">${t('player.pnow.noSongs')}</p>`;
    }

    // ── Albums panel ─────────────────────────────────────────────────────
    const albumsEl2 = document.getElementById('pnow-lib-albums');
    if (albumsEl2 && _albLib) {
      // Reuse exact same matching logic as viewArtistProfile2
      const matchedSeriesIds = new Set();
      for (const ser of (_albLib.series || [])) {
        for (const v of artistsArg) {
          if ((ser.displayName || '').toLowerCase().includes(v.toLowerCase())) {
            matchedSeriesIds.add(ser.id); break;
          }
        }
      }
      function _l1m(l1, v) {
        const l1n = l1.toLowerCase(), vn = v.toLowerCase();
        return l1n === vn || l1n.startsWith(vn + ' - ') || l1n.startsWith(vn + ' (') || l1n.startsWith(vn + '-');
      }
      const artistAlbums = (_albLib.albums || []).filter(alb => {
        if (alb.seriesId && matchedSeriesIds.has(alb.seriesId)) return true;
        const relPath = alb.path ? alb.path.slice(((alb.sourceVpath || '').length) + 1) : '';
        const l1 = relPath.split('/')[0] || '';
        return artistsArg.some(v => _l1m(l1, v));
      }).sort((a, b) => (Number.parseInt(a.year) || 9999) - (Number.parseInt(b.year) || 9999));

      if (artistAlbums.length) {
        albumsEl2.innerHTML = artistAlbums.map((alb, i) => {
          const albArtU = _albArtUrl(alb.artFile, alb.aaFile);
          const albArtHtml = albArtU
            ? `<img src="${albArtU}" alt="" loading="lazy" onerror="this.parentNode.innerHTML=noArtHtml()">`
            : noArtHtml();
          const verBadge = alb.album_version ? `<span class="alb-version-badge" title="${esc(alb.album_version)}">${esc(alb.album_version)}</span>` : '';
          return `<div class="album-card" data-pnow-alb-idx="${i}">
            <div class="album-art">${albArtHtml}<div class="play-ov"><svg width="24" height="24" viewBox="0 0 24 24" fill="white"><polygon points="5,3 19,12 5,21"/></svg></div></div>
            <div class="album-meta"><div class="album-name">${esc(alb.displayName || '—')}</div>${alb.year ? `<div class="album-year">${alb.year}${verBadge}</div>` : verBadge ? `<div class="album-year">${verBadge}</div>` : ''}</div>
          </div>`;
        }).join('');
        albumsEl2.querySelectorAll('.album-card').forEach((card, i) => {
          card.addEventListener('click', () => viewAlbumDetail(artistAlbums[i].id, 0, { backFn: goBack }));
        });
        const albTabBtn = albumsEl?.querySelector('.artpro2-tab[data-tab="albums"]');
        if (albTabBtn) albTabBtn.textContent = `Albums (${artistAlbums.length})`;
      } else {
        albumsEl2.innerHTML = `<p style="color:var(--t3);font-size:13px;">${t('player.pnow.noAlbums')}</p>`;
      }
    }
  }

  // ── 2. Last.fm: bio + similar artists (only if API key configured) ───────
  if (!libArtist || !S.lastfmHasApiKey) {
    if (bioTitle) bioTitle.textContent = '';
    return;
  }

  try {
    const [bioData, simData] = await Promise.all([
      api('GET', `api/v1/lastfm/artist-info?artist=${encodeURIComponent(libArtist)}`),
      api('GET', `api/v1/lastfm/similar-artists?artist=${encodeURIComponent(libArtist)}`),
    ]);
    if (_pnowSongFp !== forFp) return;

    // Bio
    const bio = bioData?.bio?.trim();
    if (bio && bioEl && bioTitle) {
      bioTitle.textContent = t('player.pnow.about');
      bioEl.textContent = bio;
      // Show "Read more" toggle if text overflows
      if (bioEl.scrollHeight > bioEl.clientHeight + 4) {
        if (bioMore) {
          bioMore.classList.remove('hidden');
          bioMore.onclick = () => {
            bioEl.classList.toggle('expanded');
            bioMore.textContent = bioEl.classList.contains('expanded')
              ? t('player.pnow.readLess') : t('player.pnow.readMore');
          };
        }
      }
      // Listener count as a note under bio
      if (bioData.listeners) {
        const note = document.createElement('p');
        note.style.cssText = 'font-size:11px;color:var(--t3);margin-top:6px;';
        note.textContent = t('player.pnow.listeners', { n: Number(bioData.listeners).toLocaleString() });
        bioEl.after(note);
      }
    }

    // Similar artists chips — use clean Last.fm display names when available
    const simArtists = _deduplicateSimArtists(simData?.displayArtists || simData?.artists || []);
    const _simVariantMap = simData?.displayVariantMap || {};
    if (simArtists.length && simEl && simTitle) {
      simTitle.textContent = t('player.pnow.similarArtists');
      // All displayArtists are server-confirmed to have actual albums in the library
      // (artistHasAlbums check on server). Mark all as in-library.
      const inLibrarySet = new Set(simArtists.map(a => a.toLowerCase()));
      simEl.innerHTML = simArtists.slice(0, 12).map(a =>
        `<button class="pnow-sim-chip${inLibrarySet.has(a.toLowerCase()) ? ' in-library' : ''}">${esc(a)}</button>`
      ).join('');
      simEl.querySelectorAll('.pnow-sim-chip').forEach((chip, i) => {
        chip.addEventListener('click', () => {
          const a = simArtists[i];
          const rawVars = _simVariantMap[a] || [a];
          viewArtistProfile(a.toLowerCase(), a, rawVars, () => viewPlayingNow());
        });
      });
    }
  } catch (_e) { /* Last.fm unavailable */ }
}

// Called whenever the song changes — refresh the view if it's active
function _pnowOnSongChange() {
  if (S.view !== 'playing-now') return;
  const s = S.queue[S.idx] || null;
  const newFp = s?.filepath || null;
  if (newFp === _pnowSongFp) return;
  _renderPlayingNow(true);
}

async function viewHome() {
  setTitle(t('player.title.home')); setBack(null); setNavActive('home'); S.view = 'home';
  _homeAC?.abort();
  _homeAC = (typeof AbortController !== 'undefined') ? new AbortController() : null;

  const sig = _navCancel();
  const abEx = _audioBookExclusions();
  const _cw    = (document.getElementById('content-body')?.clientWidth || 800) - 32;
  const _limit = Math.max(6, Math.floor((_cw + 10) / 130));
  const base = {
    limit: _limit,
    ...(abEx.ignoreVPaths.length            ? { ignoreVPaths:            abEx.ignoreVPaths }            : {}),
    ...(abEx.excludeFilepathPrefixes.length ? { excludeFilepathPrefixes: abEx.excludeFilepathPrefixes } : {}),
  };

  // ── Render shell immediately (greeting needs no API) ─────────
  const hr = new Date().getHours();
  const greetKey = hr < 12 ? 'player.home.greetingMorning'
                 : hr < 18 ? 'player.home.greetingAfternoon'
                 :            'player.home.greetingEvening';
  const homeDisplayName = (() => {
    const name = String(S.username || '').trim();
    if (!name) return '';
    return name.charAt(0).toLocaleUpperCase() + name.slice(1);
  })();

  setBody(`<div class="home-view">
    <div id="home-greeting-slot"><div class="home-greeting">
      <div class="home-greeting-text">${t(greetKey, { name: esc(homeDisplayName) })}</div>
    </div></div>
    <div id="home-recent-added-slot"></div>
    <div id="home-continue-slot"></div>
    <div id="home-temporal-slot"></div>
    <div id="home-mood-slot"></div>
  </div>`);

  const body = document.getElementById('content-body');
  const _allSongs = [];
  let _recentAlbumGroups = [];

  function _slot(id) { return body?.querySelector('#' + id); }

  // ── card / strip helpers ─────────────────────────────────────
  function songCard(s, showCount) {
    const url = artUrl(s['album-art'], 's');
    const artInner = url
      ? `<img src="${url}" alt="" loading="lazy" onerror="this.parentNode.innerHTML=noArtHtml()">`
      : noArtHtml();
    const sub = showCount && s._playCount
      ? `${esc(s.artist || '')}${s.artist ? ' · ' : ''}${s._playCount}×`
      : esc(s.artist || '');
    return `<div class="hc home-song" data-fp="${esc(s.filepath)}">
      <div class="hc-art">${artInner}</div>
      <div class="hc-info">
        <div class="hc-title">${esc(s.title || s.filepath.split('/').pop())}</div>
        ${sub ? `<div class="hc-sub">${sub}</div>` : ''}
      </div>
    </div>`;
  }

  function albumCard(group, idx) {
    const url = artUrl(group.art, 's');
    const artInner = url
      ? `<img src="${url}" alt="" loading="lazy" onerror="this.parentNode.innerHTML=noArtHtml()">`
      : noArtHtml();
    const fp0 = group._artFp || group.songs[0]?.filepath || '';
    const countBadge = group.songs.length > 1 ? `<span class="hc-count-badge">${group.songs.length}</span>` : '';
    return `<div class="hc home-album" data-group-idx="${idx}" data-fp="${esc(fp0)}">
      <div class="hc-art">${artInner}${countBadge}</div>
      <div class="hc-info">
        <div class="hc-title">${esc(group.label)}</div>
        ${group._artists?.size > 1 ? `<div class="hc-sub">${t('player.home.variousArtists')}</div>` : group.artist ? `<div class="hc-sub">${esc(group.artist)}</div>` : ''}
      </div>
    </div>`;
  }

  function strip(title, cards, badge) {
    const badgeHtml = badge ? `<span class="home-shelf-badge">${esc(badge)}</span>` : '';
    return `<div class="home-shelf">
      <div class="home-shelf-header">${badgeHtml}<span class="home-shelf-title">${title}</span></div>
      <div class="home-row">${cards}</div>
    </div>`;
  }

  function _bindSongCards(container) {
    container.querySelectorAll('.home-song').forEach(card => {
      card.addEventListener('click', () => {
        const fp = card.dataset.fp;
        const s = _allSongs.find(x => x.filepath === fp);
        if (s) { _setPlaySource('home', 'Home'); Player.queueAndPlay(s); }
      });
    });
  }

  function _bindAlbumCards(container) {
    container.querySelectorAll('.home-album').forEach(card => {
      card.addEventListener('click', async () => {
        const g = _recentAlbumGroups[Number.parseInt(card.dataset.groupIdx, 10)];
        if (!g) return;
        setBack(viewHome);
        if (g.dir) {
          setTitle(g.label);
          setBody('<div class="loading-state"></div>');
          try {
            const d = await api('POST', 'api/v1/db/album-songs', {
              albumDir: g.dir,
              folderOnly: true,
            });
            const allSongs = d.map(norm);
            showSongs(allSongs, null, g.label);
            const newFps = new Set(g.songs.map(s => s.filepath));
            if (newFps.size) {
              document.querySelectorAll('#content-body .song-row').forEach((row, i) => {
                if (newFps.has(allSongs[i]?.filepath)) row.classList.add('row--recently-added');
              });
            }
          } catch(e) {
            if (e.name !== 'AbortError') setBody(`<div class="empty-state">${t('player.home.recentlyAdded')}: Error</div>`);
          }
        } else {
          setTitle(g.label || '');
          showSongs(g.songs, null, g.label || '');
        }
      });
    });
  }

  function _onDemandArt(songs) {
    const _seen = new Set();
    for (const s of songs) {
      if (s['album-art'] || s.isRadio || !s.filepath || _seen.has(s.filepath)) continue;
      _seen.add(s.filepath);
      const fp = s.filepath;
      api('GET', `api/v1/files/art?fp=${encodeURIComponent(fp)}`)
        .then(d => {
          if (!d?.aaFile) return;
          for (const x of _allSongs) { if (x.filepath === fp) x['album-art'] = d.aaFile; }
          body?.querySelectorAll('.home-song, .home-album').forEach(card => {
            if (card.dataset.fp !== fp) return;
            const artDiv = card.querySelector('.hc-art');
            if (artDiv && !artDiv.querySelector('img')) {
              artDiv.insertAdjacentHTML('afterbegin', `<img src="${artUrl(d.aaFile, 's')}" alt="" loading="lazy" onerror="this.parentNode.innerHTML=noArtHtml()">`);
            }
          });
        })
        .catch(() => {});
    }
  }

  // ── Progressive fetches — fill each slot as it resolves ──────

  // 1. Most-played (~44ms) → Mood shelves
  api('POST', 'api/v1/db/stats/most-played', base, sig).catch(() => []).then(raw => {
    if (S.view !== 'home') return;
    const mostPlayed = (Array.isArray(raw) ? raw : []).map(s => { const n = norm(s); n._playCount = s.metadata?.['play-count']; return n; });
    _allSongs.push(...mostPlayed);
    const _moodMap = { nostalgia: [], current: [] };
    const cutoff = new Date().getFullYear() - 10;
    for (const s of mostPlayed) {
      const yr = Number.parseInt(s.year, 10);
      if (yr > 0 && yr < cutoff) _moodMap.nostalgia.push(s);
      else _moodMap.current.push(s);
    }
    const moodParts = [];
    if (_moodMap.nostalgia.length >= 3) moodParts.push(strip(t('player.home.moodNostalgia'), _moodMap.nostalgia.slice(0, _limit).map(s=>songCard(s,false)).join('')));
    if (_moodMap.current.length   >= 3) moodParts.push(strip(t('player.home.moodCurrent'),   _moodMap.current.slice(0, _limit).map(s=>songCard(s,false)).join('')));
    const fallback = !moodParts.length && mostPlayed.length
      ? strip(t('player.home.shelfMost'), mostPlayed.map(s => songCard(s, true)).join('')) : '';
    const html = moodParts.join('') + fallback;
    const slot = _slot('home-mood-slot');
    if (slot && html) { slot.innerHTML = html; _bindSongCards(slot); _onDemandArt(mostPlayed); }
  });

  // 2. Recently-played (~275ms) → Continue Listening shelf
  api('POST', 'api/v1/db/stats/recently-played', base, sig).catch(() => []).then(raw => {
    if (S.view !== 'home') return;
    const recentlyPlayed = (Array.isArray(raw) ? raw : []).map(norm);
    _allSongs.push(...recentlyPlayed);
    const _seenAlbums = new Set();
    const continueItems = recentlyPlayed.filter(s => {
      const key = (s.artist || '') + '|' + (s.album || s.filepath.split('/').slice(0,-1).join('/'));
      if (_seenAlbums.has(key)) return false;
      _seenAlbums.add(key); return true;
    }).slice(0, _limit);
    const html = continueItems.length
      ? strip(t('player.home.shelfContinue'), continueItems.map(s => songCard(s, false)).join('')) : '';
    const slot = _slot('home-continue-slot');
    if (slot && html) { slot.innerHTML = html; _bindSongCards(slot); _onDemandArt(continueItems); }
  });

  // 3. Recently-added (~256ms) → Recently Added albums shelf
  api('POST', 'api/v1/db/recent/added', { ...base, limit: Math.min(_limit * 6, 90) }, sig).catch(() => []).then(raw => {
    if (S.view !== 'home') return;
    const recentlyAdded = (Array.isArray(raw) ? raw : []).map(norm);
    _allSongs.push(...recentlyAdded);
    const _songDirHome = fp => {
      if (!fp) return '';
      const parts = fp.split('/');
      let dir = parts.slice(1, -1).join('/'); // strip vpath prefix + filename
      dir = dir.replace(/\/(CD|Disc|Disk|Side)\s*\d+\s*$/i, '');
      return dir;
    };
    const _raGroupMap = new Map();
    const _raGroups = [];
    for (const s of recentlyAdded) {
      const dir = _songDirHome(s.filepath);
      if (!_raGroupMap.has(dir)) {
        const label = dir.split('/').pop() || dir || '—';
        // _newDay: local-midnight (seconds) for the newest entry seen so far in this folder.
        // Songs from the same folder but an older day are NOT "new" — they just
        // happened to be in the result set because the folder was recently touched.
        const d0 = s.ts ? new Date(s.ts * 1000) : null;
        const _newDay = d0 ? Math.floor(new Date(d0.getFullYear(), d0.getMonth(), d0.getDate()).getTime() / 1000) : null;
        const grp = { label, dir, artist: s.artist || null, art: s['album-art'] || null, _artFp: s['album-art'] ? null : s.filepath, songs: [], _artists: new Set(), _newDay, _newFps: new Set() };
        _raGroupMap.set(dir, grp); _raGroups.push(grp);
      }
      const _g = _raGroupMap.get(dir);
      // Only mark a song as "new" if it was added on the same calendar day as the
      // newest song in this folder, AND deduplicate by filepath (on-demand indexer
      // can create duplicate rows for concurrent plays of the same file).
      const sd = s.ts ? new Date(s.ts * 1000) : null;
      const sDay = sd ? Math.floor(new Date(sd.getFullYear(), sd.getMonth(), sd.getDate()).getTime() / 1000) : null;
      if (sDay !== null && sDay === _g._newDay && !_g._newFps.has(s.filepath)) {
        _g._newFps.add(s.filepath);
        _g.songs.push(s);
        if (s.artist) _g._artists.add(s.artist);
      }
      if (!_g.art && s['album-art']) { _g.art = s['album-art']; _g._artFp = null; }
    }
    _recentAlbumGroups = _raGroups.slice(0, _limit);
    const html = _recentAlbumGroups.length
      ? strip(t('player.home.shelfRecentAdded'), _recentAlbumGroups.map((g, i) => albumCard(g, i)).join(''), t('player.home.badgeNew')) : '';
    const slot = _slot('home-recent-added-slot');
    if (slot && html) { slot.innerHTML = html; _bindAlbumCards(slot); _onDemandArt(recentlyAdded); }
  });

  // 4. Home-summary (~258ms) → stats strip + temporal sections
  const _sectionKeyLabels = {
    yesterday:        'player.home.shelfYesterday',
    lastWeekSameDay:  'player.home.shelfLastWeekSameDay',
    lastMonthSameDay: 'player.home.shelfLastMonthSameDay',
    lastYearSameDay:  'player.home.shelfLastYearSameDay',
  };
  api('GET', 'api/v1/db/home-summary', undefined, sig).catch(() => ({})).then(summary => {
    if (S.view !== 'home') return;
    // Patch stats strip into existing greeting
    const statsItems = [];
    if (summary.todayCount > 0) statsItems.push(`<span class="home-stat"><strong>${summary.todayCount}</strong> ${t('player.home.statToday')}</span>`);
    if (summary.weekCount  > 0) statsItems.push(`<span class="home-stat"><strong>${summary.weekCount}</strong> ${t('player.home.statWeek')}</span>`);
    if (summary.streak     > 1) statsItems.push(`<span class="home-stat home-stat-streak"><strong>${summary.streak}</strong> ${t('player.home.statStreak')}</span>`);
    if (statsItems.length) {
      const greetEl = _slot('home-greeting-slot')?.querySelector('.home-greeting');
      if (greetEl && !greetEl.querySelector('.home-stats-strip')) {
        const strip_el = document.createElement('div');
        strip_el.className = 'home-stats-strip';
        strip_el.innerHTML = statsItems.join('<span class="home-stat-sep">·</span>');
        greetEl.appendChild(strip_el);
      }
    }
    // Temporal "On This Day" sections
    const temporalSections = (summary.sections || []).map(sec => ({
      key: sec.key, songs: (sec.songs || []).map(r => norm(r)),
    })).filter(s => s.songs.length > 0);
    const allTemporal = temporalSections.flatMap(s => s.songs);
    _allSongs.push(...allTemporal);
    const temporalHtml = temporalSections.map(sec => {
      const lk = _sectionKeyLabels[sec.key];
      return lk ? strip(t(lk), sec.songs.map(s => songCard(s, false)).join('')) : '';
    }).filter(Boolean).join('');
    const slot = _slot('home-temporal-slot');
    if (slot && temporalHtml) { slot.innerHTML = temporalHtml; _bindSongCards(slot); _onDemandArt(allTemporal); }
  });
}

// ── SHORTCUTS ────────────────────────────────────────────────

async function viewShortcuts() {
  setTitle(t('player.title.shortcuts')); setBack(null); setNavActive('shortcuts'); S.view = 'shortcuts';
  _shortcutsAC?.abort();
  _shortcutsAC = (typeof AbortController !== 'undefined') ? new AbortController() : null;

  const sig = _navCancel();
  const abEx = _audioBookExclusions();
  const _cw    = (document.getElementById('content-body')?.clientWidth || 800) - 32;
  const _limit = Math.max(4, Math.floor((_cw + 10) / 130));
  const base = {
    limit: _limit,
    ...(abEx.ignoreVPaths.length             ? { ignoreVPaths:             abEx.ignoreVPaths }             : {}),
    ...(abEx.excludeFilepathPrefixes.length  ? { excludeFilepathPrefixes:  abEx.excludeFilepathPrefixes }  : {}),
  };

  // ── helpers (defined early so progressive .then() closures can use them) ─────

  function artCard(imgUrl, title, sub, attrs) {
    const artInner = imgUrl
      ? `<img src="${imgUrl}" alt="" loading="lazy" onerror="this.parentNode.innerHTML=noArtHtml()">`
      : noArtHtml();
    return `<div class="hc" ${attrs || ''}>
      <div class="hc-art">${artInner}</div>
      <div class="hc-info">
        <div class="hc-title">${esc(title)}</div>
        ${sub ? `<div class="hc-sub">${esc(sub)}</div>` : ''}
      </div>
    </div>`;
  }

  function songCard(s, showCount) {
    const url = artUrl(s['album-art'], 's');
    const artInner = url
      ? `<img src="${url}" alt="" loading="lazy" onerror="this.parentNode.innerHTML=noArtHtml()">`
      : noArtHtml();
    const sub = showCount && s._playCount
      ? `${esc(s.artist || '')}${s.artist ? ' · ' : ''}${s._playCount}×`
      : esc(s.artist || '');
    return `<div class="hc home-song" data-fp="${esc(s.filepath)}">
      <div class="hc-art">${artInner}</div>
      <div class="hc-info">
        <div class="hc-title">${esc(s.title || s.filepath.split('/').pop())}</div>
        ${sub ? `<div class="hc-sub">${sub}</div>` : ''}
      </div>
    </div>`;
  }

  function folderCard(label, attrs) {
    const art = `<svg viewBox="4 24 92 68" xmlns="http://www.w3.org/2000/svg">
      <rect width="100" height="100" style="fill:var(--surface)"/>
      <path d="M12 46 H34 L42 32 H84 Q88 32 88 37 V80 Q88 84 84 84 H16 Q12 84 12 80 Z"
            style="fill:var(--raised);stroke:var(--accent)" stroke-width="1.8" stroke-linejoin="round"/>
      <line x1="20" y1="52" x2="65" y2="52" style="stroke:var(--t3)" stroke-width="2.2" stroke-linecap="round" opacity=".75"/>
      <line x1="20" y1="61" x2="60" y2="61" style="stroke:var(--t3)" stroke-width="2.2" stroke-linecap="round" opacity=".75"/>
      <line x1="20" y1="70" x2="50" y2="70" style="stroke:var(--t3)" stroke-width="2.2" stroke-linecap="round" opacity=".75"/>
      <circle cx="74" cy="67" r="13" style="fill:var(--surface);stroke:var(--primary)" stroke-width="2.2"/>
      <polygon points="70,61 70,73 82,67" style="fill:var(--primary)"/>
    </svg>`;
    return `<div class="hc" ${attrs || ''}>
      <div class="hc-art">${art}</div>
      <div class="hc-info"><div class="hc-title">${esc(label)}</div></div>
    </div>`;
  }

  const _GRIP_ICO = `<svg width="10" height="14" viewBox="0 0 10 16" fill="currentColor" aria-hidden="true"><circle cx="2.5" cy="2" r="1.5"/><circle cx="7.5" cy="2" r="1.5"/><circle cx="2.5" cy="6" r="1.5"/><circle cx="7.5" cy="6" r="1.5"/><circle cx="2.5" cy="10" r="1.5"/><circle cx="7.5" cy="10" r="1.5"/><circle cx="2.5" cy="14" r="1.5"/><circle cx="7.5" cy="14" r="1.5"/></svg>`;
  function mkShelf(id, title, cards) {
    if (!cards) return '';
    return `<div class="home-shelf" data-shelf="${id}" draggable="true">
      <div class="home-shelf-header">
        <span class="home-grip" title="${t('player.shortcuts.gripTitle')}">${_GRIP_ICO}</span>
        <span class="home-shelf-title">${title}</span>
      </div>
      <div class="home-row">${cards}</div>
    </div>`;
  }

  // shelf order helpers
  const _ORDER_KEY = `ms2_home_order_${S.username || ''}`;
  function _savedOrder() { try { return JSON.parse(localStorage.getItem(_ORDER_KEY) || 'null'); } catch(_) { return null; } }
  function _saveOrder() {
    const v = document.getElementById('content-body')?.querySelector('.home-view');
    if (!v) return;
    const order = JSON.stringify([...v.querySelectorAll(':scope > .home-shelf')].map(s => s.dataset.shelf));
    localStorage.setItem(_ORDER_KEY, order);
    api('POST', 'api/v1/user/settings', { prefs: { home_order: order } }).catch(() => {});
  }

  // ── render skeleton immediately ──────────────────────────────
  // Playlists/vpaths shelf fills synchronously — no API needed.
  const vpathHtml    = S.vpaths.map(v    => folderCard(v,       `data-icid="${esc('vp:' + v)}" data-hid="ic:vp:${esc(v)}"`)   ).join('');
  const playlistHtml = S.playlists.map(p => folderCard(p.name,  `data-icid="${esc('pl:' + p.name)}" data-hid="ic:pl:${esc(p.name)}"`)  ).join('');
  const playlistShelfHtml = mkShelf('playlists', t('player.shortcuts.shelfPlaylists'), (vpathHtml + playlistHtml) || null);

  const _defOrder = ['radio', 'podcasts', 'playlists', 'recent', 'most'];
  const _ord = (_savedOrder() || _defOrder).filter(id => _defOrder.includes(id));
  _defOrder.forEach(id => { if (!_ord.includes(id)) _ord.push(id); });

  const _toolbarHtml = `<div class="home-toolbar"><button class="home-customize-btn">${t('player.shortcuts.btnCustomize')}</button></div>`;
  // Build initial HTML: playlists shelf has real content; data-dependent shelves are empty slot divs
  const skeletonHtml = _ord.map(id =>
    id === 'playlists' ? (playlistShelfHtml || `<div id="sc-slot-${id}"></div>`)
                       : `<div id="sc-slot-${id}"></div>`
  ).join('');
  setBody(`<div class="home-view">${_toolbarHtml}${skeletonHtml}</div>`);

  const body = document.getElementById('content-body');

  // Replace a slot div with a rendered shelf element; no-op if already navigated away
  function _fillSlot(id, shelfHtml) {
    if (S.view !== 'shortcuts') return;
    const slot = document.getElementById(`sc-slot-${id}`);
    if (!slot) return; // slot already replaced or never existed
    if (!shelfHtml) { slot.remove(); return; }
    const tmp = document.createElement('div');
    tmp.innerHTML = shelfHtml;
    const el = tmp.firstElementChild;
    slot.replaceWith(el);
    _bindShelfDrag(el);
    _applyVisibility();
  }

  // ── accumulated data for click handlers ─────────────────────
  const _allSongs = [];
  let _radStations = [], _podFeeds = [];

  // ── event delegation — click handlers on the body ────────────
  const _scACOpts = _shortcutsAC ? { signal: _shortcutsAC.signal } : {};
  body.addEventListener('click', e => {
    const view = body.querySelector('.home-view');
    // radio card
    const rsCard = e.target.closest('[data-rsid]');
    if (rsCard) { const s = _radStations.find(x => String(x.id) === rsCard.dataset.rsid); if (s) { _radioStations = _radStations; _playRadio(s); } return; }
    // podcast card
    const pfCard = e.target.closest('[data-pfid]');
    if (pfCard) { const f = _podFeeds.find(x => String(x.id) === pfCard.dataset.pfid); if (f) viewPodcastEpisodes(f); return; }
    // song card
    const sc = e.target.closest('.home-song');
    if (sc) {
      if (view?.classList.contains('home-editing')) return;
      const s = _allSongs.find(x => x.filepath === sc.dataset.fp);
      if (s) { _setPlaySource('shortcuts', 'Shortcuts'); Player.queueAndPlay(s); }
      return;
    }
    // folder / playlist card
    const ic = e.target.closest('[data-icid]');
    if (ic) {
      if (view?.classList.contains('home-editing')) return;
      const id = ic.dataset.icid;
      if (id.startsWith('vp:'))      { S.feDirStack = []; viewFiles('/' + id.slice(3), false); }
      else if (id.startsWith('pl:')) openPlaylist(id.slice(3));
    }
  }, _scACOpts);

  // ── shelf drag-to-reorder (event delegation + per-shelf listeners) ───────────
  let _dragSrc = null, _canDrag = false;
  body.addEventListener('mousedown', e => { if (e.target.closest('.home-grip')) _canDrag = true; }, _scACOpts);
  body.addEventListener('mouseup',   () => { _canDrag = false; }, _scACOpts);

  function _bindShelfDrag(shelf) {
    shelf.addEventListener('dragstart', e => {
      if (!_canDrag) { e.preventDefault(); return; }
      _dragSrc = shelf; shelf.classList.add('hs-dragging');
      e.dataTransfer.effectAllowed = 'move';
    });
    shelf.addEventListener('dragend', () => {
      _canDrag = false; _dragSrc = null;
      body.querySelectorAll('.home-shelf').forEach(s => s.classList.remove('hs-dragging', 'hs-over'));
      _saveOrder();
    });
    shelf.addEventListener('dragover', e => {
      if (!_dragSrc || _dragSrc === shelf) return;
      e.preventDefault(); e.dataTransfer.dropEffect = 'move';
      body.querySelectorAll('.home-shelf').forEach(s => s.classList.remove('hs-over'));
      shelf.classList.add('hs-over');
    });
    shelf.addEventListener('dragleave', e => {
      if (!shelf.contains(e.relatedTarget)) shelf.classList.remove('hs-over');
    });
    shelf.addEventListener('drop', e => {
      e.preventDefault();
      if (!_dragSrc || _dragSrc === shelf) return;
      const v = shelf.closest('.home-view');
      const all = [...v.querySelectorAll(':scope > .home-shelf')];
      const si = all.indexOf(_dragSrc), di = all.indexOf(shelf);
      if (si < di) v.insertBefore(_dragSrc, shelf.nextSibling);
      else         v.insertBefore(_dragSrc, shelf);
    });
  }
  // Bind drag on the playlists shelf that's already in the DOM
  body.querySelectorAll('.home-shelf').forEach(_bindShelfDrag);

  // ── visibility / customize ────────────────────────────────────
  const _HIDDEN_KEY = `ms2_home_hidden_${S.username || ''}`;
  function _loadHidden() {
    try { return new Set(JSON.parse(localStorage.getItem(_HIDDEN_KEY) || '[]')); }
    catch(_) { return new Set(); }
  }
  function _saveHidden(s) {
    const v = JSON.stringify([...s]);
    localStorage.setItem(_HIDDEN_KEY, v);
    api('POST', 'api/v1/user/settings', { prefs: { home_hidden: v } }).catch(() => {});
  }
  function _applyVisibility() {
    const view = body.querySelector('.home-view');
    if (!view) return;
    const editing = view.classList.contains('home-editing');
    const hidden  = _loadHidden();
    body.querySelectorAll('[data-hid]').forEach(card => {
      card.classList.toggle('hc-hidden', hidden.has(card.dataset.hid));
    });
    body.querySelectorAll('.home-shelf').forEach(s => {
      const all = s.querySelectorAll('[data-hid]').length;
      if (all === 0) { s.classList.remove('hs-empty'); return; }
      const vis = s.querySelectorAll('[data-hid]:not(.hc-hidden)').length;
      s.classList.toggle('hs-empty', !editing && vis === 0);
    });
  }

  _applyVisibility();

  const _custBtn = body.querySelector('.home-customize-btn');
  if (_custBtn) {
    _custBtn.addEventListener('click', () => {
      const view = body.querySelector('.home-view');
      const editing = !view.classList.contains('home-editing');
      view.classList.toggle('home-editing', editing);
      _custBtn.textContent = editing ? t('player.shortcuts.btnDone') : t('player.shortcuts.btnCustomize');
      _custBtn.classList.toggle('active', editing);
      _applyVisibility();
    });
  }

  // Customize edit mode — card click toggles visibility (captured before normal click handler)
  const _editACOpts = _shortcutsAC ? { capture: true, signal: _shortcutsAC.signal } : { capture: true };
  body.addEventListener('click', e => {
    const view = body.querySelector('.home-view');
    if (!view || !view.classList.contains('home-editing')) return;
    const card = e.target.closest('[data-hid]');
    if (!card) return;
    e.stopPropagation();
    const hidden = _loadHidden();
    const hid = card.dataset.hid;
    if (hidden.has(hid)) hidden.delete(hid); else hidden.add(hid);
    _saveHidden(hidden);
    _applyVisibility();
  }, _editACOpts);

  // ── progressive API calls — fill slots as each resolves ──────

  // Radio stations
  api('GET', 'api/v1/radio/stations', undefined, sig).catch(() => []).then(raw => {
    _radStations = Array.isArray(raw) ? raw : [];
    const html = _radStations.map(s =>
      artCard(s.img ? artUrl(s.img, 's') : null, s.name, s.genre ? s.genre.split(',')[0].trim() : '',
        `data-rsid="${esc(String(s.id))}" data-hid="rs:${esc(String(s.id))}"`)
    ).join('');
    _fillSlot('radio', mkShelf('radio', t('player.shortcuts.shelfRadio'), html || null));
  });

  // Podcasts
  api('GET', 'api/v1/podcast/feeds', undefined, sig).catch(() => []).then(raw => {
    _podFeeds = Array.isArray(raw) ? raw : [];
    if (_podFeeds.length) _podcastFeeds = _podFeeds;
    const html = _podFeeds.map(f =>
      artCard(f.img ? artUrl(f.img, 's') : null, f.title || f.url, '',
        `data-pfid="${esc(String(f.id))}" data-hid="pf:${esc(String(f.id))}"`)
    ).join('');
    _fillSlot('podcasts', mkShelf('podcasts', t('player.shortcuts.shelfPodcasts'), html || null));
  });

  // Recently played
  api('POST', 'api/v1/db/stats/recently-played', base, sig).catch(() => []).then(raw => {
    const songs = (Array.isArray(raw) ? raw : []).map(norm);
    _allSongs.push(...songs);
    _fillSlot('recent', mkShelf('recent', t('player.shortcuts.shelfRecent'), songs.map(s => songCard(s, false)).join('') || null));
  });

  // Most played → then "Because you listened to" (non-blocking, appended when ready)
  api('POST', 'api/v1/db/stats/most-played', base, sig).catch(() => []).then(async raw => {
    const mostPlayed = (Array.isArray(raw) ? raw : []).map(s => { const n = norm(s); n._playCount = s.metadata?.['play-count']; return n; });
    _allSongs.push(...mostPlayed);
    _fillSlot('most', mkShelf('most', t('player.shortcuts.shelfMost'), mostPlayed.map(s => songCard(s, true)).join('') || null));

    // "Because you listened to" — fires only after most-played renders; each shelf appends independently
    if (!S.lastfmHasApiKey || !mostPlayed.length) return;
    const artistPool = [...new Set(mostPlayed.map(s => s.artist).filter(Boolean))].slice(0, 10);
    for (let i = artistPool.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [artistPool[i], artistPool[j]] = [artistPool[j], artistPool[i]];
    }
    for (const artist of artistPool.slice(0, 2)) {
      if (S.view !== 'shortcuts') return;
      try {
        const sim = await api('GET', `api/v1/lastfm/similar-artists?artist=${encodeURIComponent(artist)}`, undefined, sig).catch(() => ({ artists: [] }));
        if (!sim.artists?.length) continue;
        const songs = await api('POST', 'api/v1/db/songs-by-artists', { artists: sim.artists.slice(0, 15), limit: _limit }, sig).catch(() => []);
        if (!songs.length || S.view !== 'shortcuts') continue;
        const normSongs = songs.map(norm);
        _allSongs.push(...normSongs);
        const key = `bec:${artist}`;
        const shelfEl = mkShelf(key, t('player.shortcuts.becauseYouListened', { artist: esc(artist) }), normSongs.map(s => songCard(s, false)).join(''));
        if (!shelfEl) continue;
        const view = body?.querySelector('.home-view');
        if (!view) continue;
        const tmp = document.createElement('div');
        tmp.innerHTML = shelfEl;
        const el = tmp.firstElementChild;
        view.appendChild(el);
        _bindShelfDrag(el);
        _applyVisibility();
      } catch(_) { /* ignore */ }
    }
  });
}

// ── FILE EXPLORER ─────────────────────────────────────────────
async function viewFiles(dir, addToStack) {
  setNavActive('files'); S.view = 'files';
  if (addToStack && S.feDir !== dir) S.feDirStack.push(S.feDir);
  S.feDir = dir || '';
  const sig = _navCancel();
  setBody('<div class="loading-state"></div>');
  try {
    const d = await api('POST', 'api/v1/file-explorer', { directory: S.feDir, sort: true, pullMetadata: true }, sig);
    renderFileExplorer(d);
  } catch(e) { if (e.name === 'AbortError') return; setBody(`<div class="empty-state">Error: ${esc(e.message)}</div>`); }
}

function renderFileExplorer(d) {
  _exitSelectMode();
  const curPath = d.path || '/';
  // Build breadcrumb — if inside Audio Content context, root crumb links back there
  const parts = curPath.replace(/^\/|\/$/g, '').split('/').filter(Boolean);
  const _inAC = !!S.audioContentReturn;
  let crumbs = _inAC
    ? `<span class="fe-crumb" data-dir="__ac__">⌂ Audio Content</span>`
    : `<span class="fe-crumb" data-dir="">${t('player.fe.rootCrumb')}</span>`;
  let cumPath = '';
  parts.forEach(p => {
    crumbs += `<span class="fe-crumb-sep">/</span>`;
    cumPath += (cumPath ? '/' : '') + p;
    crumbs += `<span class="fe-crumb" data-dir="/${cumPath}">${esc(p)}</span>`;
  });

  const feVpath = parts[0] || '';
  // A file can be deletable even when its root vpath is type=music, if it lives
  // inside a child vpath that has type=recordings and allowRecordDelete=true.
  // Check all vpathMeta entries whose filepathPrefix (or root) contains curPath.
  function canDeleteFp(fp) {
    if (!fp) return false;
    return Object.entries(S.vpathMeta || {}).some(([vpName, meta]) => {
      if ((meta.type !== 'recordings' && meta.type !== 'youtube') || !meta.allowRecordDelete) return false;
      // Direct root vpath match: fp starts with vpName/
      if (fp.startsWith(vpName + '/') || fp === vpName) return true;
      // Child vpath: fp starts with parentVpath/filepathPrefix
      if (meta.parentVpath && meta.filepathPrefix) {
        return fp.startsWith(meta.parentVpath + '/' + meta.filepathPrefix);
      }
      return false;
    });
  }
  // canDeleteFp expects paths without a leading slash (same format as song.filepath).
  // d.path from the API always has a leading slash, so strip it before checking.
  const _curNorm = curPath.replace(/^\//, '').replace(/\/$/, '');
  const canDelete = canDeleteFp(_curNorm + '/') || canDeleteFp(_curNorm);

  const dirs = (d.directories || []).map(dir => `
    <div class="fe-dir" data-dir="${esc(curPath + dir.name)}">
      <svg class="fe-icon" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/></svg>
      <span class="fe-name">${esc(dir.name)}</span>
      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="color:var(--t3);flex-shrink:0"><polyline points="9,18 15,12 9,6"/></svg>
    </div>`).join('');

  let _feAudioIdx = 0;
  const files = (d.files || []).map(file => {
    const meta = file.metadata?.metadata;
    const fp   = file.metadata?.filepath;
    const ciAttr    = fp ? ` data-ci="${_feAudioIdx++}"` : '';
    const rowCheck  = fp ? '<div class="row-check"></div>' : '';
    const rowClass  = fp ? 'fe-file song-row' : 'fe-file';
    const title  = meta?.title  || file.name;
    const artist = meta?.artist || '';
    const artU   = artUrl(meta?.['album-art'], 's');
    const thumb  = artU
      ? `<img class="fe-thumb" src="${artU}" alt="" loading="lazy" onerror="this.outerHTML='<svg class=fe-icon width=16 height=16 viewBox=&quot;0 0 24 24&quot; fill=none stroke=currentColor stroke-width=2><path d=&quot;M9 18V5l12-2v13&quot;/><circle cx=6 cy=18 r=3/><circle cx=18 cy=16 r=3/></svg>'">`
      : `<svg class="fe-icon" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M9 18V5l12-2v13"/><circle cx="6" cy="18" r="3"/><circle cx="18" cy="16" r="3"/></svg>`;
    return `
      <div class="${rowClass}"${ciAttr} data-fp="${esc(fp || '')}" data-name="${esc(file.name)}">
        ${rowCheck}
        ${thumb}
        <div class="fe-name">
          <div>${esc(title)}</div>
          ${artist ? `<div style="font-size:11px;color:var(--t2);margin-top:1px">${esc(artist)}</div>` : ''}
        </div>
        <span class="fe-sub">${esc(file.type?.toUpperCase() || '')}</span>
        <div class="fe-actions">
          <button class="fe-act fe-play-btn" title="${t('player.fe.btnPlay')}">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="currentColor"><polygon points="5,3 19,12 5,21"/></svg>
          </button>
          <button class="fe-act fe-add-btn" title="${t('player.fe.btnAddQueue')}">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="12" y1="5" x2="12" y2="19"/><line x1="5" y1="12" x2="19" y2="12"/></svg>
          </button>
          <a class="fe-act" href="${fp ? dlUrl(fp) : '#'}" download="${esc(file.name)}" title="${t('player.fe.btnDownload')}" onclick="event.stopPropagation()">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7,10 12,15 17,10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
          </a>
          ${canDelete ? `<button class="fe-act fe-del-btn" title="${t('player.fe.btnDeleteRec')}" style="color:var(--red,#e05)">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="3,6 5,6 21,6"/><path d="M19,6l-1,14H6L5,6"/><path d="M10,11v6"/><path d="M14,11v6"/><path d="M9,6V4h6v2"/></svg>
          </button>` : ''}
        </div>
      </div>`;
  }).join('');

  // Back button logic — when inside an Audio Content context, back goes to Audio Content root
  const hasBack = S.feDirStack.length > 0;
  if (S.audioContentReturn) setNavActive('podcasts');
  const _backFromStack = () => { const prev = S.feDirStack.pop(); S.feDir = prev; viewFiles(prev, false); };
  const _backToAC = S.audioContentReturn
    ? () => { const fn = S.audioContentReturn; S.audioContentReturn = null; fn(); }
    : null;
  const _backToSearch = S.feSearchReturn
    ? () => { const fn = S.feSearchReturn; S.feSearchReturn = null; fn(); }
    : null;
  setBack(hasBack ? _backFromStack : (_backToAC || _backToSearch));
  setTitle(parts.length ? parts[parts.length - 1] : t('player.fe.titleFallback'));

  // Play all for directory
  const dirSongs = (d.files || [])
    .filter(f => f.metadata?.filepath)
    .map(f => norm(f.metadata));

  document.getElementById('play-all-btn').onclick = () => {
    if (dirSongs.length) { Player.setQueue(dirSongs, 0); toast(t('player.toast.playingSongs', { count: dirSongs.length })); }
  };
  document.getElementById('add-all-btn').onclick = () => {
    if (dirSongs.length) { Player.addAll(dirSongs); }
  };
  S.curSongs = dirSongs;

  // Show zip + select buttons when the directory has audio files, hide them otherwise
  const _feZipName = parts.length ? parts[parts.length - 1] : null;
  const zipBtn = document.getElementById('zip-dl-btn');
  const selBtn = document.getElementById('select-mode-btn');
  if (dirSongs.length && _feZipName) {
    if (zipBtn) { zipBtn.classList.remove('hidden'); zipBtn.onclick = () => _zipDownload(dirSongs, _feZipName); }
    if (selBtn) { selBtn.classList.remove('hidden'); selBtn.onclick = _toggleSelectMode; }
  } else {
    if (zipBtn) { zipBtn.classList.add('hidden'); zipBtn.onclick = null; }
    if (selBtn) { selBtn.classList.add('hidden'); selBtn.onclick = null; }
  }

  const body = document.getElementById('content-body');
  body.innerHTML = `
    <div class="fe-breadcrumb">${crumbs}</div>
    <div class="fe-filter-row">
      <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>
      <input id="fe-filter" class="fe-filter-input" type="text" placeholder="${t('player.fe.filterPlaceholder')}" autocomplete="off">
      <span id="fe-match-count" class="fe-match-count"></span>
      <button id="fe-filter-clear" class="fe-filter-clear hidden" title="${t('player.fe.filterClearTitle')}">✕</button>
      ${S.canUpload && curPath !== '/' ? `<button id="fe-upload-btn" class="fe-upload-btn" title="${t('player.fe.btnUploadTitle')}"><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="16,16 12,12 8,16"/><line x1="12" y1="12" x2="12" y2="21"/><path d="M20.39 18.39A5 5 0 0 0 18 9h-1.26A8 8 0 1 0 3 16.3"/></svg> ${t('player.fe.btnUpload')}</button>` : ''}
      ${S.allowId3Edit && S.isAdmin && curPath !== '/' && (d.files?.length > 0) ? `<button id="fe-tw-btn" class="fe-tw-btn" title="${t('player.tw.btnOpenTitle')}"><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg> ${t('player.tw.btnOpen')}</button>` : ''}
    </div>
    <div id="fe-grid" class="fe-grid">${dirs}<div class="song-list">${files}</div></div>`;

  // Live filter
  const filterInput  = body.querySelector('#fe-filter');
  const filterClear  = body.querySelector('#fe-filter-clear');
  const matchCount   = body.querySelector('#fe-match-count');
  const grid         = body.querySelector('#fe-grid');

  // Restore saved filter from previous navigation level
  if (S.feFilter) { filterInput.value = S.feFilter; }

  function applyFilter() {
    const q = filterInput.value.trim().toLowerCase();
    filterClear.classList.toggle('hidden', !q);
    const rows = grid.querySelectorAll('.fe-dir, .fe-file');
    let visible = 0;
    rows.forEach(row => {
      const name = (row.dataset.dir || row.dataset.name || '').split('/').pop().toLowerCase();
      const artist = row.querySelector('[style*="color:var(--t2)"]')?.textContent?.toLowerCase() || '';
      const matches = !q || name.includes(q) || artist.includes(q);
      row.classList.toggle('fe-hidden', !matches);
      if (matches) visible++;
    });
    matchCount.textContent = q ? (visible !== 1 ? t('player.fe.filterResults', { count: visible }) : t('player.fe.filterResult', { count: visible })) : '';
  }

  filterInput.addEventListener('input', () => { S.feFilter = filterInput.value; applyFilter(); });
  filterClear.addEventListener('click', () => { filterInput.value = ''; S.feFilter = ''; filterInput.focus(); applyFilter(); });

  // Apply restored filter immediately if one exists
  if (S.feFilter) applyFilter();

  // Upload button
  body.querySelector('#fe-upload-btn')?.addEventListener('click', () => openUploadModal(curPath));
  // Tag Workshop button
  body.querySelector('#fe-tw-btn')?.addEventListener('click', () => viewTagWorkshop(S.feDir, false));

  // Breadcrumb navigation
  body.querySelectorAll('.fe-crumb').forEach(el => {
    el.addEventListener('click', () => {
      if (el.dataset.dir === '__ac__') {
        // Return to Audio Content root
        const fn = S.audioContentReturn;
        S.audioContentReturn = null;
        S.feDirStack = [];
        if (fn) fn(); else viewPodcasts();
      } else {
        S.feDirStack = [];
        viewFiles(el.dataset.dir || '', false);
      }
    });
  });
  // Navigate into directory — filter persists (saved in S.feFilter)
  body.querySelectorAll('.fe-dir').forEach(el => {
    el.addEventListener('click', () => viewFiles(el.dataset.dir, true));
  });
  // File actions
  body.querySelectorAll('.fe-file').forEach(el => {
    el.addEventListener('click', e => {
      if (e.target.closest('.fe-act')) return;
      const fp = el.dataset.fp;
      if (!fp) return;
      // Select-mode: toggle selection instead of playing
      if (S.selectMode && el.dataset.ci != null) {
        const i = Number.parseInt(el.dataset.ci);
        if (S.selectedIdxs.has(i)) { S.selectedIdxs.delete(i); el.classList.remove('selected'); }
        else { S.selectedIdxs.add(i); el.classList.add('selected'); }
        _updateZipCount();
        return;
      }
      const found = dirSongs.find(s => s.filepath === fp);
      if (found) Player.queueAndPlay(found);
    });
  });
  body.querySelectorAll('.fe-play-btn').forEach(btn => {
    btn.addEventListener('click', e => {
      e.stopPropagation();
      const fp = btn.closest('.fe-file').dataset.fp;
      const found = dirSongs.find(s => s.filepath === fp);
      if (found) Player.playSingle(found);
    });
  });
  body.querySelectorAll('.fe-add-btn').forEach(btn => {
    btn.addEventListener('click', e => {
      e.stopPropagation();
      const fp = btn.closest('.fe-file').dataset.fp;
      const found = dirSongs.find(s => s.filepath === fp);
      if (found) Player.addSong(found);
    });
  });
  body.querySelectorAll('.fe-del-btn').forEach(btn => {
    btn.addEventListener('click', e => {
      e.stopPropagation();
      const fileEl = btn.closest('.fe-file');
      const fp = fileEl.dataset.fp;
      const fname = fp.split('/').pop();
      showConfirmModal(
        t('player.fe.deleteTitle'),
        t('player.fe.deleteBody', { name: fname }),
        async () => {
          try {
            await api('DELETE', 'api/v1/files/recording', { filepath: fp });
            toast(t('player.toast.feDeleted', { name: fname }));
            fileEl.remove();
            const idx = S.curSongs.findIndex(s => s.filepath === fp);
            if (idx !== -1) S.curSongs.splice(idx, 1);
            const qi = S.queue.findIndex(s => s.filepath === fp);
            if (qi !== -1) {
              S.queue.splice(qi, 1); _qvsVersion++;
              if (S.idx > qi) S.idx--;
              else if (S.idx === qi) S.idx = Math.min(S.idx, S.queue.length - 1);
              persistQueue();
              refreshQueueUI();
            }
          } catch(_e) {
            toast(t('player.toast.recordingDeleteFailed'));
          }
        }
      );
    });
  });

  // On-demand art for files not yet scanned / no embedded art cached
  const _feMissing = dirSongs.filter(s => !s['album-art'] && !s.isRadio && !s.isPodcast && s.filepath);
  if (_feMissing.length) {
    _feMissing.forEach(s => {
      api('GET', `api/v1/files/art?fp=${encodeURIComponent(s.filepath)}`)
        .then(d => {
          if (!d?.aaFile) return;
          s['album-art'] = d.aaFile;
          const fileEl = body.querySelector(`.fe-file[data-fp="${CSS.escape(s.filepath)}"]`);
          if (!fileEl) return;
          const svgIcon = fileEl.querySelector('svg.fe-icon');
          if (!svgIcon) return;
          const img = document.createElement('img');
          img.className = 'fe-thumb';
          img.alt = '';
          img.loading = 'lazy';
          img.src = artUrl(d.aaFile, 's');
          img.onerror = function() { this.outerHTML = '<svg class="fe-icon" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M9 18V5l12-2v13"/><circle cx="6" cy="18" r="3"/><circle cx="18" cy="16" r="3"/></svg>'; };
          svgIcon.replaceWith(img);
        })
        .catch(() => {});
    });
  }
}

// ── TAG WORKSHOP ──────────────────────────────────────────────
// Folder-based bulk tag editor. Navigate to any folder, check the files
// you want to update, fill in the shared fields (artist/album/year/genre),
// and hit Apply — each file is rewritten via the existing tags/write API.
// Individual files can also be edited inline (all fields incl. title/track).

let _twFiles = []; // workshop session state — array of tag objects per file

async function viewTagWorkshop(dir, addToStack) {
  if (!S.isAdmin) return;
  setNavActive('files'); S.view = 'tagworkshop';
  if (addToStack !== false && S.feDir !== dir) S.feDirStack.push(S.feDir);
  S.feDir = dir || '';
  const sig = _navCancel();
  setBody('<div class="loading-state"></div>');
  document.getElementById('play-all-btn').onclick = null;
  document.getElementById('add-all-btn').onclick  = null;
  try {
    const pathParam = (S.feDir || '').replace(/^\//, '');
    const [dbData, feData] = await Promise.all([
      api('GET', 'api/v1/tagworkshop/folder?path=' + encodeURIComponent(pathParam), undefined, sig),
      api('POST', 'api/v1/file-explorer', { directory: S.feDir, sort: true }, sig),
    ]);
    renderTagWorkshop(dbData.files || [], feData.directories || [], feData.path || (S.feDir || '/'));
  } catch(e) { if (e.name === 'AbortError') return; setBody(`<div class="empty-state">Error: ${esc(e.message)}</div>`); }
}

function renderTagWorkshop(dbFiles, dirs, curPath) {
  const parts = (curPath || '/').replace(/^\/|\/$/g, '').split('/').filter(Boolean);

  // Breadcrumb (stays in workshop on click)
  let crumbs = `<span class="fe-crumb" data-dir="">${t('player.fe.rootCrumb')}</span>`;
  let cumPath = '';
  parts.forEach(p => {
    crumbs += `<span class="fe-crumb-sep">/</span>`;
    cumPath += (cumPath ? '/' : '') + p;
    crumbs += `<span class="fe-crumb" data-dir="/${cumPath}">${esc(p)}</span>`;
  });

  // Subdirectory entries (navigate within workshop)
  const dirsHtml = dirs.map(dir => `
    <div class="fe-dir tw-nav-dir" data-dir="${esc(curPath + dir.name)}">
      <svg class="fe-icon" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M22 19a2 2 0 0 1-2 2H4a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h5l2 3h9a2 2 0 0 1 2 2z"/></svg>
      <span class="fe-name">${esc(dir.name)}</span>
      <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="color:var(--t3);flex-shrink:0"><polyline points="9,18 15,12 9,6"/></svg>
    </div>`).join('');

  // Build unified file list with MB data
  _twFiles = dbFiles.map((f, i) => ({
    i,
    fp:      f.vpath + '/' + f.filepath,
    filepath: f.filepath,
    vpath:   f.vpath,
    name:    f.filepath.split('/').pop(),
    title:   String(f.title  ?? ''),
    artist:  String(f.artist ?? ''),
    album:   String(f.album  ?? ''),
    year:    String(f.year   ?? ''),
    track:   String(f.track  ?? ''),
    disk:    String(f.disk   ?? ''),
    genre:   String(f.genre  ?? ''),
    mb_title:  f.mb_title  ?? null,
    mb_artist: f.mb_artist ?? null,
    mb_album:  f.mb_album  ?? null,
    mb_year:   f.mb_year   != null ? String(f.mb_year) : null,
    mb_track:  f.mb_track  != null ? String(f.mb_track) : null,
    mb_release_id: f.mb_release_id ?? null,
    tag_status: f.tag_status ?? null,
    acoustid_status:      f.acoustid_status      ?? null,
    mb_enrichment_status: f.mb_enrichment_status ?? null,
    hasMb: f.mb_release_id != null,
  }));

  const mbFiles  = _twFiles.filter(f => f.hasMb);
  const manFiles = _twFiles.filter(f => !f.hasMb);

  // Build per-file diff (only fields that differ)
  function getDiffs(f) {
    const n = s => String(s ?? '').trim().toLowerCase();
    const diffs = [];
    if (f.mb_title  != null && n(f.mb_title)  !== n(f.title))  diffs.push({ field: t('metadata.title'),  cur: f.title,  mb: f.mb_title  });
    if (f.mb_artist != null && n(f.mb_artist) !== n(f.artist)) diffs.push({ field: t('metadata.artist'), cur: f.artist, mb: f.mb_artist });
    if (f.mb_album  != null && n(f.mb_album)  !== n(f.album))  diffs.push({ field: t('metadata.album'),  cur: f.album,  mb: f.mb_album  });
    if (f.mb_year   != null && f.mb_year !== String(f.year ?? ''))   diffs.push({ field: t('metadata.year'),  cur: f.year,  mb: f.mb_year   });
    if (f.mb_track  != null && f.mb_track !== String(f.track ?? '')) diffs.push({ field: t('metadata.track'), cur: f.track, mb: f.mb_track  });
    return diffs;
  }

  // Inline edit form HTML (shared between MB and manual rows)
  function inlineFormHtml(f) {
    return `<div class="tw-inline-form hidden" data-idx="${f.i}">
      <div class="tw-form-grid">
        <div class="tw-form-row"><label>${t('metadata.title')}</label><input class="tw-inp" data-field="title" value="${esc(f.title)}"></div>
        <div class="tw-form-row"><label>${t('metadata.artist')}</label><input class="tw-inp" data-field="artist" value="${esc(f.artist)}"></div>
        <div class="tw-form-row"><label>${t('metadata.album')}</label><input class="tw-inp" data-field="album" value="${esc(f.album)}"></div>
        <div class="tw-form-row"><label>${t('metadata.year')}</label><input class="tw-inp tw-inp-sm" data-field="year" value="${esc(f.year)}"></div>
        <div class="tw-form-row"><label>${t('metadata.genre')}</label><input class="tw-inp" data-field="genre" value="${esc(f.genre)}"></div>
        <div class="tw-form-row"><label>${t('metadata.track')}</label><input class="tw-inp tw-inp-sm" data-field="track" value="${esc(f.track)}"></div>
        <div class="tw-form-row"><label>${t('metadata.disc')}</label><input class="tw-inp tw-inp-sm" data-field="disk" value="${esc(f.disk)}"></div>
      </div>
      <div class="tw-inline-btns">
        <button class="tw-save-btn" data-idx="${f.i}">${t('player.tw.btnSave')}</button>
        <button class="tw-cancel-btn" data-idx="${f.i}">${t('player.tw.btnCancel')}</button>
        <span class="tw-inline-status"></span>
      </div>
    </div>`;
  }

  // ── MB section ──
  let mbSectionHtml = '';
  if (mbFiles.length > 0) {
    const pendingCount = mbFiles.filter(f => f.tag_status !== 'accepted').length;
    const mbRows = mbFiles.map(f => {
      const diffs = getDiffs(f);
      const isAccepted = f.tag_status === 'accepted';
      const diffsHtml = diffs.length > 0
        ? diffs.map(d => `<span class="tw-diff-item"><span class="tw-diff-field">${esc(d.field)}:</span> <span class="tw-diff-cur">${esc(d.cur || '—')}</span><span class="tw-diff-arrow">→</span><span class="tw-diff-mb">${esc(d.mb || '—')}</span></span>`).join('')
        : `<span class="tw-mb-match">✓ ${t('player.tw.mbTagsOk')}</span>`;
      const acceptBtn = isAccepted
        ? `<span class="tw-accepted-tag">✓ ${t('player.tw.mbAccepted')}</span>`
        : `<button class="tw-accept-mb-btn" data-idx="${f.i}">${t('player.tw.mbAcceptBtn')}</button>`;
      return `<div class="tw-row" data-idx="${f.i}" data-mb="1">
        <div class="tw-row-main">
          <input type="checkbox" class="tw-check tw-mb-check" ${isAccepted ? 'disabled' : 'checked'}>
          <div class="tw-row-info">
            <div class="tw-row-title">${esc(f.title || f.name)}</div>
            <div class="tw-row-path">${esc(f.name)}</div>
            <div class="tw-diff-list">${diffsHtml}</div>
          </div>
          ${acceptBtn}
          <button class="tw-edit-btn" title="${t('player.tw.btnEditTitle')}" data-idx="${f.i}">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
          </button>
        </div>
        ${inlineFormHtml(f)}
      </div>`;
    }).join('');

    mbSectionHtml = `
      <div class="tw-section-header">${t('player.tw.mbSection', { n: mbFiles.length })}</div>
      <div class="tw-bulk-bar">
        <div class="tw-bulk-actions">
          <button class="tw-sel-btn" id="tw-mb-sel-all">${t('player.tw.btnSelectAll')}</button>
          <button class="tw-sel-btn" id="tw-mb-sel-none">${t('player.tw.btnSelectNone')}</button>
          <button class="btn-sm btn-primary-sm" id="tw-mb-accept-all" ${pendingCount === 0 ? 'disabled' : ''}>${t('player.tw.mbAcceptAll', { n: pendingCount })}</button>
        </div>
        <div id="tw-mb-progress" class="tw-progress hidden"></div>
      </div>
      <div class="tw-file-list">${mbRows}</div>`;
  }

  // ── Manual section ──
  let manSectionHtml = '';
  if (manFiles.length > 0) {
    // Classify per file
    const notFingerprinted = manFiles.filter(f => f.acoustid_status !== 'found');
    const enrichEligible   = manFiles.filter(f => f.acoustid_status === 'found');
    const totalCanEnrich   = enrichEligible.filter(f => !f.mb_enrichment_status || f.mb_enrichment_status === 'pending' || f.mb_enrichment_status === 'no_data' || f.mb_enrichment_status === 'error').length;
    const totalCanScan     = notFingerprinted.length;

    function enrichHint(f) {
      if (f.acoustid_status !== 'found') return `<span class="tw-enrich-hint tw-enrich-none">${t('player.tw.enrichHintNoAcoustid')}</span>`;
      if (f.mb_enrichment_status === 'no_data') return `<span class="tw-enrich-hint tw-enrich-warn">${t('player.tw.enrichHintNoData')}</span>`;
      if (f.mb_enrichment_status === 'error')   return `<span class="tw-enrich-hint tw-enrich-warn">${t('player.tw.enrichHintError')}</span>`;
      return `<span class="tw-enrich-hint tw-enrich-ok">${t('player.tw.enrichHintQueued')}</span>`;
    }

    const manRows = manFiles.map(f => {
      const tagLine = [f.artist, f.album, f.year].filter(Boolean).join(' · ');
      return `<div class="tw-row" data-idx="${f.i}">
        <div class="tw-row-main">
          <input type="checkbox" class="tw-check tw-man-check" checked>
          <div class="tw-row-info">
            <div class="tw-row-title">${esc(f.title || f.name)}</div>
            <div class="tw-row-path">${esc(f.name)}</div>
            ${tagLine ? `<div class="tw-row-tags">${esc(tagLine)}</div>` : ''}
            ${enrichHint(f)}
          </div>
          <button class="tw-edit-btn" title="${t('player.tw.btnEditTitle')}" data-idx="${f.i}">
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"/><path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"/></svg>
          </button>
        </div>
        ${inlineFormHtml(f)}
      </div>`;
    }).join('');

    const actionBtns = [
      totalCanScan > 0
        ? `<button class="btn-sm btn-accent-sm" id="tw-scan-btn">${t('player.tw.scanBtn', { n: totalCanScan })}</button>`
        : '',
      totalCanEnrich > 0
        ? `<button class="btn-sm btn-accent-sm" id="tw-enrich-btn">${t('player.tw.enrichBtn', { n: totalCanEnrich })}</button>`
        : '',
    ].filter(Boolean).join('');

    manSectionHtml = `
      ${mbFiles.length > 0 ? `<div class="tw-section-header" style="margin-top:24px">${t('player.tw.manualSection', { n: manFiles.length })}</div>` : ''}
      <div class="tw-bulk-bar">
        <div class="tw-bulk-hint">${t('player.tw.bulkHint')}</div>
        ${actionBtns ? `<div class="tw-enrich-bar">${actionBtns}<span class="tw-enrich-note" id="tw-enrich-note">${t('player.tw.enrichNote')}</span></div>` : ''}
        <div class="tw-bulk-fields">
          <div class="tw-form-row"><label>${t('metadata.artist')}</label><input class="tw-inp tw-inp-wide" id="tw-b-artist" placeholder="${t('player.tw.bulkBlankHint')}"></div>
          <div class="tw-form-row"><label>${t('metadata.album')}</label><input class="tw-inp tw-inp-wide" id="tw-b-album" placeholder="${t('player.tw.bulkBlankHint')}"></div>
          <div class="tw-form-row"><label>${t('metadata.year')}</label><input class="tw-inp tw-inp-sm" id="tw-b-year" placeholder="${t('player.tw.bulkBlankHint')}"></div>
          <div class="tw-form-row"><label>${t('metadata.genre')}</label><input class="tw-inp tw-inp-wide" id="tw-b-genre" placeholder="${t('player.tw.bulkBlankHint')}"></div>
        </div>
        <div class="tw-bulk-actions">
          <button class="tw-sel-btn" id="tw-sel-all">${t('player.tw.btnSelectAll')}</button>
          <button class="tw-sel-btn" id="tw-sel-none">${t('player.tw.btnSelectNone')}</button>
          <button class="btn-sm btn-primary-sm" id="tw-apply-btn">${t('player.tw.btnApply', { count: manFiles.length })}</button>
        </div>
        <div id="tw-bulk-progress" class="tw-progress hidden"></div>
      </div>
      <div class="tw-file-list">${manRows}</div>`;
  }

  const isEmpty = mbFiles.length === 0 && manFiles.length === 0;

  const body = document.getElementById('content-body');
  body.innerHTML = `
    <div class="tw-header">
      <button class="tw-back-btn">
        <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="15,18 9,12 15,6"/></svg>
        ${t('player.tw.btnBrowse')}
      </button>
      <div class="fe-breadcrumb" style="margin:0;padding:0;flex:1">${crumbs}</div>
    </div>
    ${dirsHtml ? `<div class="fe-grid" style="margin-bottom:14px">${dirsHtml}</div>` : ''}
    ${isEmpty
      ? `<div class="empty-state">${t('player.tw.emptyFolder')}</div>`
      : mbSectionHtml + manSectionHtml}`;

  setTitle(parts.length ? parts[parts.length - 1] : t('player.tw.title'));

  // ── Wire events ──

  body.querySelector('.tw-back-btn')?.addEventListener('click', () => viewFiles(S.feDir, false));
  body.querySelectorAll('.fe-crumb').forEach(el =>
    el.addEventListener('click', () => viewTagWorkshop(el.dataset.dir || '', false)));
  body.querySelectorAll('.tw-nav-dir').forEach(el =>
    el.addEventListener('click', () => viewTagWorkshop(el.dataset.dir, true)));

  // MB: select all/none
  function updateMbCount() {
    const all = body.querySelectorAll('.tw-mb-check').length;
    const n = body.querySelectorAll('.tw-mb-check:checked').length;
    const btn = body.querySelector('#tw-mb-accept-all');
    if (btn) { btn.textContent = t('player.tw.mbAcceptAll', { n }); btn.disabled = n === 0; }
  }
  body.querySelectorAll('.tw-mb-check').forEach(cb => cb.addEventListener('change', updateMbCount));
  body.querySelector('#tw-mb-sel-all')?.addEventListener('click', () => {
    body.querySelectorAll('.tw-mb-check:not(:disabled)').forEach(cb => cb.checked = true); updateMbCount();
  });
  body.querySelector('#tw-mb-sel-none')?.addEventListener('click', () => {
    body.querySelectorAll('.tw-mb-check:not(:disabled)').forEach(cb => cb.checked = false); updateMbCount();
  });

  // MB: bulk accept
  body.querySelector('#tw-mb-accept-all')?.addEventListener('click', async () => {
    const checked = [...body.querySelectorAll('.tw-row[data-mb]')]
      .filter(row => row.querySelector('.tw-mb-check:checked'))
      .map(row => Number.parseInt(row.dataset.idx));
    if (!checked.length) { toast(t('player.tw.toastNoneSelected')); return; }

    const progressEl = body.querySelector('#tw-mb-progress');
    const acceptAllBtn = body.querySelector('#tw-mb-accept-all');
    acceptAllBtn.disabled = true;
    progressEl.classList.remove('hidden');

    let done = 0, errors = 0;
    for (const idx of checked) {
      const f = _twFiles[idx];
      if (!f || !f.hasMb) continue;
      progressEl.textContent = t('player.tw.progressSaving', { done, total: checked.length });
      try {
        const r = await api('POST', 'api/v1/tagworkshop/accept-track', { filepath: f.filepath, vpath: f.vpath });
        f.tag_status = 'accepted';
        const row = body.querySelector(`.tw-row[data-idx="${idx}"]`);
        if (row) {
          const cb = row.querySelector('.tw-mb-check');
          if (cb) { cb.checked = false; cb.disabled = true; }
          const btn = row.querySelector('.tw-accept-mb-btn');
          if (btn) btn.replaceWith(Object.assign(document.createElement('span'), { className: 'tw-accepted-tag', textContent: '✓ ' + t('player.tw.mbAccepted') }));
        }
        done++;
      } catch(_) { errors++; done++; }
    }

    progressEl.textContent = errors
      ? t('player.tw.progressDoneErrors', { done: done - errors, errors })
      : t('player.tw.progressDone', { done });
    updateMbCount();
    toast(errors
      ? t('player.tw.toastDoneErrors', { done: done - errors, errors })
      : t('player.tw.toastDone', { done }));
  });

  // MB: per-file accept
  body.querySelectorAll('.tw-accept-mb-btn').forEach(btn => {
    btn.addEventListener('click', async () => {
      const idx = Number.parseInt(btn.dataset.idx);
      const f = _twFiles[idx];
      if (!f || !f.hasMb) return;
      btn.disabled = true;
      try {
        const r = await api('POST', 'api/v1/tagworkshop/accept-track', { filepath: f.filepath, vpath: f.vpath });
        f.tag_status = 'accepted';
        const cb = body.querySelector(`.tw-row[data-idx="${idx}"] .tw-mb-check`);
        if (cb) { cb.checked = false; cb.disabled = true; }
        btn.replaceWith(Object.assign(document.createElement('span'), { className: 'tw-accepted-tag', textContent: '✓ ' + t('player.tw.mbAccepted') }));
        updateMbCount();
        toast(t('player.tw.toastDone', { done: 1 }));
      } catch(e) {
        btn.disabled = false;
        toast('✗ ' + (e.message || 'Error'));
      }
    });
  });

  // Manual: select all/none
  function updateManCount() {
    const n = body.querySelectorAll('.tw-man-check:checked').length;
    const btn = body.querySelector('#tw-apply-btn');
    if (btn) btn.textContent = t('player.tw.btnApply', { count: n });
  }
  body.querySelectorAll('.tw-man-check').forEach(cb => cb.addEventListener('change', updateManCount));
  body.querySelector('#tw-sel-all')?.addEventListener('click', () => {
    body.querySelectorAll('.tw-man-check').forEach(cb => cb.checked = true); updateManCount();
  });
  body.querySelector('#tw-sel-none')?.addEventListener('click', () => {
    body.querySelectorAll('.tw-man-check').forEach(cb => cb.checked = false); updateManCount();
  });

  // Manual: scan unfingerprinted files with AcoustID
  body.querySelector('#tw-scan-btn')?.addEventListener('click', async () => {
    const btn = body.querySelector('#tw-scan-btn');
    const noteEl = body.querySelector('#tw-enrich-note');
    btn.disabled = true;
    const filesToScan = _twFiles.filter(f => !f.hasMb && f.acoustid_status !== 'found')
      .map(f => ({ filepath: f.filepath, vpath: f.vpath }));
    try {
      const r = await api('POST', 'api/v1/acoustid/scan-files', { files: filesToScan });
      if (noteEl) noteEl.textContent = t('player.tw.scanQueued', { n: r.queued });
      toast(t('player.tw.scanToast', { n: r.queued }));
    } catch(e) {
      btn.disabled = false;
      toast('✗ ' + (e.message || 'Error'));
    }
  });

  // Manual: enrich with MusicBrainz
  body.querySelector('#tw-enrich-btn')?.addEventListener('click', async () => {
    const btn = body.querySelector('#tw-enrich-btn');
    const noteEl = body.querySelector('#tw-enrich-note');
    btn.disabled = true;
    const filesToEnrich = _twFiles.filter(f => !f.hasMb && f.acoustid_status === 'found')
      .map(f => ({ filepath: f.filepath, vpath: f.vpath }));
    try {
      const r = await api('POST', 'api/v1/tagworkshop/enrich/files', { files: filesToEnrich });
      if (noteEl) noteEl.textContent = t('player.tw.enrichQueued', { n: r.queued });
      toast(t('player.tw.enrichToast', { n: r.queued }));
    } catch(e) {
      btn.disabled = false;
      toast('✗ ' + (e.message || 'Error'));
    }
  });

  // Manual: bulk apply
  body.querySelector('#tw-apply-btn')?.addEventListener('click', async () => {
    const artist = body.querySelector('#tw-b-artist')?.value.trim() || '';
    const album  = body.querySelector('#tw-b-album')?.value.trim()  || '';
    const year   = body.querySelector('#tw-b-year')?.value.trim()   || '';
    const genre  = body.querySelector('#tw-b-genre')?.value.trim()  || '';
    if (!artist && !album && !year && !genre) { toast(t('player.tw.toastNothingToApply')); return; }

    const checked = [...body.querySelectorAll('.tw-row:not([data-mb])')]
      .filter(row => row.querySelector('.tw-man-check:checked'))
      .map(row => Number.parseInt(row.dataset.idx));
    if (!checked.length) { toast(t('player.tw.toastNoneSelected')); return; }

    const progressEl = body.querySelector('#tw-bulk-progress');
    const applyBtn   = body.querySelector('#tw-apply-btn');
    applyBtn.disabled = true;
    progressEl.classList.remove('hidden');

    let done = 0, errors = 0;
    for (const idx of checked) {
      const f = _twFiles[idx];
      if (!f) continue;
      progressEl.textContent = t('player.tw.progressSaving', { done, total: checked.length });
      const data = { filepath: f.fp };
      if (artist) data.artist = artist;
      if (album)  data.album  = album;
      if (year)   data.year   = year;
      if (genre)  data.genre  = genre;
      try {
        const r = await api('POST', 'api/v1/admin/tags/write', data);
        if (artist) f.artist = artist;
        if (album)  f.album  = album;
        if (year)   f.year   = year;
        if (genre)  f.genre  = genre;
        const row = body.querySelector(`.tw-row[data-idx="${idx}"]`);
        if (row) {
          const gEl = row.querySelector('.tw-row-tags');
          const tl  = [f.artist, f.album, f.year].filter(Boolean).join(' · ');
          if (gEl) gEl.textContent = tl;
        }
        done++;
      } catch(_) { errors++; done++; }
    }
    progressEl.textContent = errors
      ? t('player.tw.progressDoneErrors', { done: done - errors, errors })
      : t('player.tw.progressDone', { done });
    applyBtn.disabled = false;
    toast(errors
      ? t('player.tw.toastDoneErrors', { done: done - errors, errors })
      : t('player.tw.toastDone', { done }));
  });

  // Shared: inline edit toggle
  body.querySelectorAll('.tw-edit-btn').forEach(btn => {
    btn.addEventListener('click', e => {
      e.stopPropagation();
      const idx  = Number.parseInt(btn.dataset.idx);
      const form = body.querySelector(`.tw-inline-form[data-idx="${idx}"]`);
      if (!form) return;
      const isOpen = !form.classList.contains('hidden');
      body.querySelectorAll('.tw-inline-form').forEach(f => f.classList.add('hidden'));
      body.querySelectorAll('.tw-edit-btn').forEach(b => b.classList.remove('tw-edit-active'));
      if (!isOpen) { form.classList.remove('hidden'); btn.classList.add('tw-edit-active'); }
    });
  });

  // Shared: inline save
  body.querySelectorAll('.tw-save-btn').forEach(btn => {
    btn.addEventListener('click', async () => {
      const idx  = Number.parseInt(btn.dataset.idx);
      const form = body.querySelector(`.tw-inline-form[data-idx="${idx}"]`);
      const f    = _twFiles[idx];
      if (!f || !form) return;
      const statusEl = form.querySelector('.tw-inline-status');
      btn.disabled = true;
      if (statusEl) { statusEl.textContent = t('player.npId3.saving'); statusEl.className = 'tw-inline-status'; }
      const data = { filepath: f.fp };
      form.querySelectorAll('.tw-inp').forEach(inp => { data[inp.dataset.field] = inp.value; });
      try {
        const r = await api('POST', 'api/v1/admin/tags/write', data);
        ['title','artist','album','year','genre','track','disk'].forEach(k => { if (data[k] !== undefined) f[k] = data[k]; });
        const row = body.querySelector(`.tw-row[data-idx="${idx}"]`);
        if (row) {
          const tEl = row.querySelector('.tw-row-title');
          if (tEl && f.title) tEl.textContent = f.title;
          const tl  = [f.artist, f.album, f.year].filter(Boolean).join(' · ');
          const gEl = row.querySelector('.tw-row-tags');
          if (gEl) gEl.textContent = tl;
        }
        if (statusEl) { statusEl.textContent = '✓ ' + t('player.tw.savedOk'); statusEl.className = 'tw-inline-status tw-status-ok'; }
      } catch(e) {
        if (statusEl) { statusEl.textContent = '✗ ' + (e.message || 'Error'); statusEl.className = 'tw-inline-status tw-status-err'; }
      }
      btn.disabled = false;
    });
  });

  // Shared: inline cancel
  body.querySelectorAll('.tw-cancel-btn').forEach(btn => {
    btn.addEventListener('click', () => {
      const idx  = Number.parseInt(btn.dataset.idx);
      const form = body.querySelector(`.tw-inline-form[data-idx="${idx}"]`);
      if (form) form.classList.add('hidden');
      body.querySelectorAll('.tw-edit-btn').forEach(b => b.classList.remove('tw-edit-active'));
    });
  });
}



// ── AUTO-DJ VIEW ──────────────────────────────────────────────
async function viewAutoDJ() {
  setTitle(t('player.title.autoDj')); setBack(null); setNavActive('autodj'); S.view = 'autodj';
  S.curSongs = [];
  // Ensure vpaths are loaded (may be empty if checkSession had a hiccup)
  if (!S.vpaths.length) {
    try {
      const d = await api('GET', 'api/v1/db/status');
      if (d.vpaths && d.vpaths.length) {
        S.vpaths = d.vpaths;
        if (!S.djVpaths.length) S.djVpaths = [...S.vpaths];
      }
    } catch(_) {}
  }
  document.getElementById('play-all-btn').onclick = null;
  document.getElementById('add-all-btn').onclick  = null;

  const body = document.getElementById('content-body');
  body.innerHTML = `
    <div class="autodj-panel">
      <div class="autodj-hero">
        <div class="autodj-icon">🎲</div>
        <h2>Auto-DJ</h2>
        <p>${t('player.autodj.heroDesc')}</p>
      </div>
      <button class="autodj-toggle${S.autoDJ ? ' on' : ''}" id="autodj-main-btn">
        ${S.autoDJ ? t('player.autodj.btnStop') : t('player.autodj.btnStart')}
      </button>
      <div class="autodj-status${S.autoDJ ? ' on' : ''}" id="autodj-status-msg">
        ${S.autoDJ ? t('player.autodj.statusOn') : t('player.autodj.statusOff')}
      </div>
      <div class="autodj-opts">
        <h4>${t('player.autodj.settingsHeading')}</h4>
        ${S.vpaths.length > 1 ? `
        <div class="autodj-opt-row autodj-opt-col">
          <div>
            <div class="autodj-opt-label">${t('player.autodj.sourcesLabel')}</div>
            <div class="autodj-opt-hint">${t('player.autodj.sourcesHint')}</div>
          </div>
          <div class="dj-vpath-pills" id="dj-vpaths">
            ${S.vpaths.map(v => `<button class="dj-vpath-pill${S.djVpaths.includes(v) ? ' on' : ''}" data-vpath="${esc(v)}">${esc(v)}</button>`).join('')}
          </div>
        </div>` : ''}
        <div class="autodj-opt-row">
          <div>
            <div class="autodj-opt-label">${t('player.autodj.ratingLabel')}</div>
            <div class="autodj-opt-hint">${t('player.autodj.ratingHint')}</div>
          </div>
          <select class="autodj-select" id="dj-min-rating">
            <option value="0" ${S.djMinRating===0?'selected':''}>${t('player.autodj.ratingAny')}</option>
            <option value="2" ${S.djMinRating===2?'selected':''}>★ (1 star)</option>
            <option value="4" ${S.djMinRating===4?'selected':''}>★★ (2 stars)</option>
            <option value="6" ${S.djMinRating===6?'selected':''}>★★★ (3 stars)</option>
            <option value="8" ${S.djMinRating===8?'selected':''}>★★★★ (4 stars)</option>
            <option value="10" ${S.djMinRating===10?'selected':''}>★★★★★ (5 stars)</option>
          </select>
        </div>
        <div class="autodj-opt-row">
          <div>
            <div class="autodj-opt-label">${t('player.autodj.similarLabel')}</div>
            <div class="autodj-opt-hint">${t('player.autodj.similarHint')}${S.lastfmHasApiKey ? '' : ' <em>' + t('player.autodj.similarHintNoKey') + '</em>'}</div>
          </div>
          <label class="toggle-sw" ${S.lastfmHasApiKey ? '' : `title="${t('player.autodj.similarNoKeyTitle')}"`} style="${S.lastfmHasApiKey ? '' : 'opacity:.4;pointer-events:none;'}">
            <input type="checkbox" id="dj-similar" ${S.djSimilar && S.lastfmHasApiKey ? 'checked' : ''} ${S.lastfmHasApiKey ? '' : 'disabled'}>
            <span class="toggle-sw-track"><span class="toggle-sw-thumb"></span></span>
          </label>
        </div>
        <div class="autodj-opt-row">
          <div>
            <div class="autodj-opt-label">${t('player.autodj.crossfadeLabel')}</div>
            <div class="autodj-opt-hint">${t('player.autodj.crossfadeHint')}</div>
          </div>
          <div class="xf-ctrl">
            <input type="range" id="xf-slider-dj" class="xf-slider" min="0" max="12" step="1" value="${S.crossfade}">
            <span id="xf-val-dj" class="xf-val">${S.crossfade === 0 ? t('player.autodj.crossfadeOff') : S.crossfade + 's'}</span>
          </div>
        </div>
${_webAnimSupported ? `
        <div class="autodj-opt-row">
          <div>
            <div class="autodj-opt-label">${t('player.autodj.diceLabel')}</div>
            <div class="autodj-opt-hint">${t('player.autodj.diceHint')}</div>
          </div>
          <label class="toggle-sw">
            <input type="checkbox" id="dj-dice-toggle" ${S.djDice ? 'checked' : ''}>
            <span class="toggle-sw-track"><span class="toggle-sw-thumb"></span></span>
          </label>
        </div>` : ''}
        <div class="autodj-opt-row autodj-opt-col">
          <div class="autodj-filter-header">
            <div>
              <div class="autodj-opt-label">${t('player.autodj.filterLabel')}</div>
              <div class="autodj-opt-hint">${t('player.autodj.filterHint')}</div>
            </div>
            <label class="toggle-sw">
              <input type="checkbox" id="dj-filter-toggle" ${S.djFilterEnabled ? 'checked' : ''}>
              <span class="toggle-sw-track"><span class="toggle-sw-thumb"></span></span>
            </label>
          </div>
          <div class="dj-filter-tags" id="dj-filter-tags">
            ${S.djFilterWords.map(w => `<span class="dj-filter-tag">${esc(w)}<button class="dj-filter-tag-rm" data-word="${esc(w)}" title="${t('player.autodj.filterTagRemove')}">×</button></span>`).join('')}
            <input class="dj-filter-input" id="dj-filter-input" type="text" placeholder="${t('player.autodj.filterPlaceholder')}" ${S.djFilterEnabled ? '' : 'disabled'}>
          </div>
        </div>
        <div class="autodj-opt-row autodj-opt-col">
          <div class="autodj-filter-header">
            <div>
              <div class="autodj-opt-label">${t('player.autodj.genreFilterLabel')}</div>
              <div class="autodj-opt-hint">${t('player.autodj.genreFilterHint')}</div>
            </div>
            <label class="toggle-sw">
              <input type="checkbox" id="dj-genre-toggle" ${S.djGenreEnabled ? 'checked' : ''}>
              <span class="toggle-sw-track"><span class="toggle-sw-thumb"></span></span>
            </label>
          </div>
          <div class="dj-genre-ctrl" id="dj-genre-ctrl" style="${S.djGenreEnabled ? '' : 'display:none'}">
            <div class="dj-genre-mode">
              <label class="dj-genre-radio">
                <input type="radio" name="dj-genre-mode" value="whitelist" ${S.djGenreMode === 'whitelist' ? 'checked' : ''}> ${t('player.autodj.genreWhitelist')}
              </label>
              <label class="dj-genre-radio">
                <input type="radio" name="dj-genre-mode" value="blacklist" ${S.djGenreMode === 'blacklist' ? 'checked' : ''}> ${t('player.autodj.genreBlacklist')}
              </label>
            </div>
            <div class="dj-filter-tags" id="dj-genre-pills">
              ${S.djGenres.map(g => {
                const isGrp = g.startsWith('GROUP:');
                const label = isGrp ? '\u229e ' + g.slice(6) : g;
                return `<span class="dj-filter-tag${isGrp ? ' dj-genre-group-tag' : ''}">${esc(label)}<button class="dj-genre-rm" data-genre="${esc(g)}" title="${t('player.autodj.genreRemove')}">×</button></span>`;
              }).join('')}
            </div>
            <div class="dj-genre-add">
              <input type="text" id="dj-genre-filter" class="dj-filter-input dj-genre-filter-input" placeholder="${t('player.autodj.genreFilterPlaceholder')}">
              <select class="autodj-select dj-genre-select" id="dj-genre-select">
                <option value="">${t('player.autodj.genreSelectPlaceholder')}</option>
              </select>
            </div>
          </div>
        </div>
        <div class="autodj-opt-row">
          <div>
            <div class="autodj-opt-label">${t('player.autodj.bpmContinuity')}</div>
          </div>
          <label class="toggle-sw">
            <input type="checkbox" id="dj-bpm-cont" ${S.djBpmContinuity ? 'checked' : ''}>
            <span class="toggle-sw-track"><span class="toggle-sw-thumb"></span></span>
          </label>
        </div>
        <div class="autodj-opt-row" id="dj-bpm-tol-row" style="${S.djBpmContinuity ? '' : 'display:none'}">
          <div>
            <div class="autodj-opt-label">${t('player.autodj.bpmTolerance', { n: S.djBpmTolerance })}</div>
          </div>
          <div class="xf-ctrl">
            <input type="range" id="dj-bpm-tol" class="xf-slider" min="1" max="20" step="1" value="${S.djBpmTolerance}">
            <span id="dj-bpm-tol-val" class="xf-val">±${S.djBpmTolerance}</span>
          </div>
        </div>
        <div class="autodj-opt-row" id="dj-bpm-base-row" style="${S.djBpmContinuity ? '' : 'display:none'}">
          <div>
            <div class="autodj-opt-label">${t('player.autodj.bpmBase')}</div>
            <small id="dj-bpm-base-range" style="opacity:0.6;font-size:0.8em">${S.djBpmBase != null ? (S.djBpmBase - S.djBpmTolerance) + '\u2013' + (S.djBpmBase + S.djBpmTolerance) : t('player.autodj.bpmBaseAuto')}</small>
          </div>
          <div class="xf-ctrl">
            <input type="number" id="dj-bpm-base" class="xf-val" min="20" max="300" step="1" value="${S.djBpmBase ?? ''}" placeholder="\u2014" style="width:4em;text-align:right">
          </div>
        </div>
        <div class="autodj-opt-row" style="flex-direction:column;align-items:stretch;gap:0">
          <div style="display:flex;align-items:center;justify-content:space-between">
            <div style="display:flex;align-items:center;gap:6px">
              <div class="autodj-opt-label" style="margin-bottom:0">${t('player.autodj.harmonicMixing')}</div>
              <button id="dj-harmonic-info-btn" class="dj-info-btn" title="${t('player.autodj.camelotWheelTitle')}"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="16" x2="12" y2="12"/><line x1="12" y1="8" x2="12.01" y2="8"/></svg></button>
            </div>
            <label class="toggle-sw">
              <input type="checkbox" id="dj-harmonic" ${S.djHarmonicMixing ? 'checked' : ''}>
              <span class="toggle-sw-track"><span class="toggle-sw-thumb"></span></span>
            </label>
          </div>
          <div id="dj-harmonic-info-panel" style="display:none"></div>
        </div>
      </div>
    </div>`;

  document.getElementById('autodj-main-btn').onclick = () => setAutoDJ(!S.autoDJ);
  document.getElementById('dj-min-rating').onchange = e => {
    S.djMinRating = Number.parseInt(e.target.value);
    localStorage.setItem(_djKey('min_rating'), S.djMinRating);
    _syncPrefs();
  };
  document.getElementById('dj-similar').addEventListener('change', e => {
    S.djSimilar = e.target.checked;
    S.djSimilar
      ? localStorage.setItem(_uKey('dj_similar'), '1')
      : localStorage.removeItem(_uKey('dj_similar'));
    _syncPrefs();
    _syncQueueLabel();
    toast(t(S.djSimilar ? 'player.toast.similarArtistsOn' : 'player.toast.similarArtistsOff'));
  });
  const xfSliderDj = document.getElementById('xf-slider-dj');
  const xfValDj    = document.getElementById('xf-val-dj');
  xfSliderDj.addEventListener('input', () => {
    setCrossfade(xfSliderDj.value);
  });
  if (_webAnimSupported) {
    document.getElementById('dj-dice-toggle').addEventListener('change', e => {
      S.djDice = e.target.checked;
      S.djDice
        ? localStorage.setItem(_uKey('dj_dice'), '1')
        : localStorage.removeItem(_uKey('dj_dice'));
      _syncPrefs();
      toast(t(S.djDice ? 'player.toast.diceRollOn' : 'player.toast.diceRollOff'));
    });
  }

  // ── Keyword Filter handlers ────────────────────────────────
  function _saveFilterWords() {
    localStorage.setItem('ms2_dj_filter_words_' + (S.username || ''), JSON.stringify(S.djFilterWords));
    _syncPrefs();
  }
  function _renderFilterTag(word) {
    const span = document.createElement('span');
    span.className = 'dj-filter-tag';
    span.innerHTML = `${esc(word)}<button class="dj-filter-tag-rm" data-word="${esc(word)}" title="${t('player.autodj.filterTagRemove')}">×</button>`;
    return span;
  }
  document.getElementById('dj-filter-toggle').addEventListener('change', e => {
    S.djFilterEnabled = e.target.checked;
    S.djFilterEnabled
      ? localStorage.setItem('ms2_dj_filter_on_' + (S.username || ''), '1')
      : localStorage.removeItem('ms2_dj_filter_on_' + (S.username || ''));
    const inp = document.getElementById('dj-filter-input');
    if (inp) inp.disabled = !S.djFilterEnabled;
    _syncPrefs();
    toast(t(S.djFilterEnabled ? 'player.toast.keywordFilterOn' : 'player.toast.keywordFilterOff'));
  });
  const filterInp = document.getElementById('dj-filter-input');
  if (filterInp) {
    filterInp.addEventListener('keydown', e => {
      if (e.key !== 'Enter' && e.key !== ',') return;
      e.preventDefault();
      const word = filterInp.value.trim().toLowerCase();
      if (!word || S.djFilterWords.includes(word)) { filterInp.value = ''; return; }
      S.djFilterWords.push(word);
      _saveFilterWords();
      const container = document.getElementById('dj-filter-tags');
      container.insertBefore(_renderFilterTag(word), filterInp);
      filterInp.value = '';
    });
  }
  document.getElementById('dj-filter-tags').addEventListener('click', e => {
    const btn = e.target.closest('.dj-filter-tag-rm');
    if (!btn) return;
    const word = btn.dataset.word;
    S.djFilterWords = S.djFilterWords.filter(w => w !== word);
    _saveFilterWords();
    btn.closest('.dj-filter-tag').remove();
  });

  // ── Genre Filter handlers ──────────────────────────────────
  function _saveGenres() {
    localStorage.setItem('ms2_dj_genre_list_' + (S.username || ''), JSON.stringify(S.djGenres));
    _syncPrefs();
  }
  function _renderGenrePill(genre) {
    const span = document.createElement('span');
    const isGrp = genre.startsWith('GROUP:');
    const label = isGrp ? '\u229e ' + genre.slice(6) : genre;
    span.className = 'dj-filter-tag' + (isGrp ? ' dj-genre-group-tag' : '');
    span.innerHTML = `${esc(label)}<button class="dj-genre-rm" data-genre="${esc(genre)}" title="${t('player.autodj.genreRemove')}">×</button>`;
    return span;
  }
  document.getElementById('dj-genre-toggle').addEventListener('change', e => {
    S.djGenreEnabled = e.target.checked;
    S.djGenreEnabled
      ? localStorage.setItem('ms2_dj_genre_on_' + (S.username || ''), '1')
      : localStorage.removeItem('ms2_dj_genre_on_' + (S.username || ''));
    const ctrl = document.getElementById('dj-genre-ctrl');
    if (ctrl) ctrl.style.display = S.djGenreEnabled ? '' : 'none';
    _syncPrefs();
    toast(t(S.djGenreEnabled ? 'player.toast.genreFilterOn' : 'player.toast.genreFilterOff'));
  });
  document.querySelectorAll('input[name="dj-genre-mode"]').forEach(radio => {
    radio.addEventListener('change', () => {
      S.djGenreMode = radio.value;
      localStorage.setItem('ms2_dj_genre_mode_' + (S.username || ''), S.djGenreMode);
      _syncPrefs();
    });
  });
  document.getElementById('dj-genre-pills').addEventListener('click', e => {
    const btn = e.target.closest('.dj-genre-rm');
    if (!btn) return;
    const genre = btn.dataset.genre;
    S.djGenres = S.djGenres.filter(g => g !== genre);
    _saveGenres();
    btn.closest('.dj-filter-tag').remove();
    _rebuildGenreSelect(); // rebuild from cached groups data
  });
  // Shared add function used by the dropdown's `change` event.
  function _djAddGenre(genre) {
    if (!genre || S.djGenres.includes(genre)) return;
    S.djGenres.push(genre);
    _saveGenres();
    const pillsEl2 = document.getElementById('dj-genre-pills');
    if (pillsEl2) pillsEl2.appendChild(_renderGenrePill(genre));
    _rebuildGenreSelect();
  }
  // Auto-add when an option is picked from the dropdown
  document.getElementById('dj-genre-select').addEventListener('change', e => {
    const v = e.target.value;
    if (!v) return;
    _djAddGenre(v);
    e.target.value = '';
    // Clear the filter input and restore the full list after picking
    const filterEl = document.getElementById('dj-genre-filter');
    if (filterEl) { filterEl.value = ''; _rebuildGenreSelect(); }
  });
  // Filter the genre select as the user types
  document.getElementById('dj-genre-filter').addEventListener('input', e => {
    _rebuildGenreSelect(e.target.value);
  });
  // Build optgroup select from _djGenreGroupsCache, optionally filtered by a search string
  function _rebuildGenreSelect(filter = '') {
    const f = filter.toLowerCase();
    const sel = document.getElementById('dj-genre-select');
    if (!sel || !_djGenreGroupsCache) return;
    sel.innerHTML = `<option value="">${t('player.autodj.genreSelectPlaceholder')}</option>`;
    for (const grp of _djGenreGroupsCache) {
      const grpVal = 'GROUP:' + grp.name;
      const grpSelected = S.djGenres.includes(grpVal);
      let availSubs = grp.genres.filter(g => !S.djGenres.includes(g.genre));
      if (f) availSubs = availSubs.filter(g => g.genre.toLowerCase().includes(f));
      const showGrpOpt = !grpSelected && (!f || grp.name.toLowerCase().includes(f));
      if (!showGrpOpt && availSubs.length === 0) continue;
      const og = document.createElement('optgroup');
      const grpTotal = grp.genres.reduce((s, g) => s + (g.cnt || 0), 0);
      og.label = grp.name + ' \u2014 ' + grpTotal.toLocaleString() + ' songs';
      if (showGrpOpt) {
        const allOpt = document.createElement('option');
        allOpt.value = grpVal;
        allOpt.textContent = '\u229e All ' + grp.name;
        og.appendChild(allOpt);
      }
      for (const g of availSubs) {
        const opt = document.createElement('option');
        opt.value = g.genre;
        opt.textContent = '\u00a0\u00a0' + g.genre + ' (' + (g.cnt || 0) + ')';
        og.appendChild(opt);
      }
      if (og.children.length > 0) sel.appendChild(og);
    }
  }
  // Populate genre select from /api/v1/db/genre-groups (groups + counts)
  api('GET', 'api/v1/db/genre-groups').then(data => {
    if (!data?.genres) return;
    if (data.groups) {
      // Build cache with counts
      const cntMap = new Map(data.genres.map(g => [g.genre, g.cnt]));
      _djGenreGroupsCache = data.groups.map(grp => ({
        name: grp.name,
        genres: grp.genres.map(g => {
          const name = typeof g === 'string' ? g : g.genre;
          return { genre: name, cnt: cntMap.get(name) ?? (typeof g === 'object' ? (g.cnt || 0) : 0) };
        }),
      }));
    } else {
      // No groups configured — create a single virtual group from the flat genre list
      _djGenreGroupsCache = [{ name: 'All genres', genres: data.genres }];
    }
    _rebuildGenreSelect();
  }).catch(() => {}); /* no-op: genre select stays empty on error */

  // ── BPM Continuity handlers ────────────────────────────────
  document.getElementById('dj-bpm-cont').addEventListener('change', e => {
    S.djBpmContinuity = e.target.checked;
    S.djBpmContinuity
      ? localStorage.setItem(_djKey('bpm_cont'), '1')
      : localStorage.removeItem(_djKey('bpm_cont'));
    if (!S.djBpmContinuity) _bpmHistoryClear(); // reset on next DJ call
    const tolRow = document.getElementById('dj-bpm-tol-row');
    if (tolRow) tolRow.style.display = S.djBpmContinuity ? '' : 'none';
    const baseRow2 = document.getElementById('dj-bpm-base-row');
    if (baseRow2) baseRow2.style.display = S.djBpmContinuity ? '' : 'none';
    _syncPrefs();
    _syncQueueLabel();
  });
  const bpmTolSlider = document.getElementById('dj-bpm-tol');
  const bpmTolVal    = document.getElementById('dj-bpm-tol-val');
  if (bpmTolSlider) {
    bpmTolSlider.addEventListener('input', () => {
      S.djBpmTolerance = Number.parseInt(bpmTolSlider.value, 10);
      localStorage.setItem(_djKey('bpm_tol'), S.djBpmTolerance);
      if (bpmTolVal) bpmTolVal.textContent = '±' + S.djBpmTolerance;
      const _baseRange = document.getElementById('dj-bpm-base-range');
      if (_baseRange && S.djBpmBase != null) {
        _baseRange.textContent = (S.djBpmBase - S.djBpmTolerance) + '\u2013' + (S.djBpmBase + S.djBpmTolerance);
      }
      _syncPrefs();
      _syncQueueLabel();
    });
  }
  const bpmBaseInput = document.getElementById('dj-bpm-base');
  const bpmBaseRange = document.getElementById('dj-bpm-base-range');
  if (bpmBaseInput) {
    bpmBaseInput.addEventListener('input', () => {
      const _v = Number.parseInt(bpmBaseInput.value, 10);
      if (_v >= 20 && _v <= 300) {
        S.djBpmBase = _v;
        localStorage.setItem(_djKey('bpm_base'), String(_v));
        _bpmHistoryClear(); // pin the base — rolling average no longer needed
      } else {
        S.djBpmBase = null;
        localStorage.removeItem(_djKey('bpm_base'));
      }
      if (bpmBaseRange) {
        bpmBaseRange.textContent = S.djBpmBase != null
          ? (S.djBpmBase - S.djBpmTolerance) + '\u2013' + (S.djBpmBase + S.djBpmTolerance)
          : t('player.autodj.bpmBaseAuto');
      }
      _syncPrefs();
      _syncQueueLabel();
    });
  }
  document.getElementById('dj-harmonic').addEventListener('change', e => {
    S.djHarmonicMixing = e.target.checked;
    S.djHarmonicMixing
      ? localStorage.setItem(_djKey('harmonic'), '1')
      : localStorage.removeItem(_djKey('harmonic'));
    if (!S.djHarmonicMixing) { _camelotAnchor = null; _camelotAnchorNeighbours = null; } // re-lock on next DJ call
    _syncPrefs();
    _syncQueueLabel();
  });
  const harmonicInfoBtn   = document.getElementById('dj-harmonic-info-btn');
  const harmonicInfoPanel = document.getElementById('dj-harmonic-info-panel');
  if (harmonicInfoBtn && harmonicInfoPanel) {
    harmonicInfoBtn.addEventListener('click', () => {
      const _open = harmonicInfoPanel.style.display !== 'none';
      harmonicInfoPanel.style.display = _open ? 'none' : '';
      harmonicInfoBtn.classList.toggle('active', !_open);
      if (!_open) {
        harmonicInfoPanel.innerHTML = _camelotWheelHTML(_camelotAnchor ?? _currentCamelot ?? null);
        const cwSvg = harmonicInfoPanel.querySelector('#cw-svg');
        const cwTip = harmonicInfoPanel.querySelector('#cw-tip');
        if (cwSvg && cwTip) {
          let _cwTipT = null;
          const _cwShow = g => {
            clearTimeout(_cwTipT);
            const key  = g.dataset.ckey;
            const name = g.dataset.kname;
            const fill = g.querySelector('path')?.getAttribute('fill') ?? 'var(--t1,#eee)';
            cwTip.innerHTML = `<span style="font-size:26px;font-weight:800;color:${fill};font-family:system-ui,sans-serif;letter-spacing:.02em">${key}</span><span style="font-size:14px;color:var(--t1,#eee);font-family:system-ui,sans-serif">${name}</span>`;
          };
          const _cwHide = () => { _cwTipT = setTimeout(() => { cwTip.innerHTML = ''; }, 150); };
          cwSvg.addEventListener('mouseover', e => { const g = e.target.closest('.cw-seg'); if (g) _cwShow(g); });
          cwSvg.addEventListener('mouseout',  e => { if (!e.relatedTarget?.closest?.('.cw-seg')) _cwHide(); });
          cwSvg.addEventListener('touchstart', e => {
            const t2 = e.touches[0];
            const g = document.elementFromPoint(t2.clientX, t2.clientY)?.closest?.('.cw-seg');
            if (!g) return;
            e.preventDefault();
            _cwShow(g);
          }, { passive: false });
        }
      }
    });
  }

  const pillsEl = document.getElementById('dj-vpaths');
  if (pillsEl) {
    pillsEl.addEventListener('click', e => {
      const pill = e.target.closest('.dj-vpath-pill');
      if (!pill) return;
      const v = pill.dataset.vpath;
      const idx = S.djVpaths.indexOf(v);
      if (idx === -1) {
        S.djVpaths.push(v);
        pill.classList.add('on');
      } else if (S.djVpaths.length > 1) {
        S.djVpaths.splice(idx, 1);
        pill.classList.remove('on');
      } else {
        toast(t('player.toast.djMinSourcesRequired'));
        return;
      }
      localStorage.setItem(_djKey('vpaths'), JSON.stringify(S.djVpaths));
      S.djIgnore = []; // reset play history when sources change
      S.djArtistHistory = [];
      localStorage.removeItem(_djKey('ignore'));
      localStorage.removeItem(_djKey('artist_history'));
      _syncPrefs();
    });
  }
}

// ── GENRE VIEW ────────────────────────────────────────────────

/**
 * Lightweight virtual-scroll album grid.
 * Renders only the rows within the viewport (+ BUFS buffer rows).
 * @param {Array}    albums    - raw album objects from the API
 * @param {Function} buildCard - (album) => HTML string for one card
 * @param {Function} onClick   - (album, cardEl) => called on card click
 */
function _mountAlbumVScroll(albums, buildCard, onClick, containerEl) {
  const GAP = 20, BUFS = 3;
  let cols = 0, rowH = 0, fRow = -1, lRow = -1;

  const body = containerEl || document.getElementById('content-body');
  body.innerHTML = '<div class="album-grid" id="vgrid"></div>';
  const grid = document.getElementById('vgrid');

  function measure() {
    const gw = grid.clientWidth;
    if (!gw) return false;
    const probe = document.createElement('div');
    probe.className = 'album-card';
    probe.style.cssText = 'visibility:hidden;pointer-events:none;position:relative';
    probe.innerHTML = '<div class="album-art" style="aspect-ratio:1"></div>'
                    + '<div class="album-info"><div class="album-name">X</div></div>';
    grid.appendChild(probe);
    rowH = probe.offsetHeight;
    const pw = probe.offsetWidth;
    grid.removeChild(probe);
    cols = pw > 0 ? Math.max(1, Math.round((gw + GAP) / (pw + GAP))) : 1;
    return rowH > 0;
  }

  function render(force) {
    if (!cols || !rowH) { if (!measure()) return; }
    const nRows = Math.ceil(albums.length / cols);
    const sTop  = body.scrollTop;
    const vH    = body.clientHeight;
    const nF    = Math.max(0, Math.floor(sTop / (rowH + GAP)) - BUFS);
    const nL    = Math.min(nRows - 1, Math.ceil((sTop + vH) / (rowH + GAP)) + BUFS);
    if (!force && nF === fRow && nL === lRow) return;
    fRow = nF; lRow = nL;
    grid.style.paddingTop    = `${fRow * (rowH + GAP)}px`;
    grid.style.paddingBottom = `${Math.max(0, nRows - lRow - 1) * (rowH + GAP)}px`;
    const html = [];
    for (let i = fRow * cols; i <= Math.min(albums.length - 1, (lRow + 1) * cols - 1); i++) {
      html.push(buildCard(albums[i], i));
    }
    grid.innerHTML = html.join('');
  }

  let _rafA = false;
  body.addEventListener('scroll', () => {
    if (_rafA || !grid.isConnected) return;
    _rafA = true;
    requestAnimationFrame(() => { _rafA = false; if (grid.isConnected) render(false); });
  });
  const ro = new ResizeObserver(() => requestAnimationFrame(() => {
    if (!grid.isConnected) { ro.disconnect(); return; }
    if (measure()) { fRow = -1; lRow = -1; render(true); }
  }));
  ro.observe(grid);
  grid.addEventListener('click', e => {
    const card = e.target.closest('.album-card');
    if (card) onClick(albums[Number.parseInt(card.dataset.i)], card);
  });

  render(true);
}

// Super-category buckets for genre grouping — first match wins
const GENRE_BUCKETS = [
  ['Rock',               /\b(rock|punk|metal|grunge|emo|hardcore|alternative|indie|shoegaze|post.rock|new.wave|prog(ressive)?|glam|gothic|psychedel|garage|britpop|surf|math.rock|noise.rock|skate)\b/i],
  ['Electronic',         /\b(electro(nic)?|techno|house|trance|drum.?n?.?bass|dnb|d&b|ambient|synth|rave|edm|idm|breakbeat|dubstep|chillout|chill(?!i)|deep.house|trip.hop|downtempo|jungle|acid|minimal(?! folk|ist)|dance(?!.pop)|club|industrial|dark.wave|ebm|vaporwave|lo.?fi|hardstyle|psytrance|psybient|dub(?!step)|gabber|neurofunk|liquid drum|deathstep)\b/i],
  ['Pop',                /\b(pop(?!.punk|.rock)|disco|bubblegum|teen.pop|j.?pop|k.?pop|c.?pop|city.pop)\b/i],
  ['Hip-Hop & R&B',      /\b(hip.?hop|rap|r&b|rnb|neo.?soul|urban|grime|trap|drill|afroswing)\b/i],
  ['Soul & Funk',        /\b(soul|funk|motown|rhythm.and.blues|boogie|northern.soul|groove(?! metal))\b/i],
  ['Jazz & Blues',       /\b(jazz|blues|swing|bebop|be.bop|fusion|bossa|latin.jazz|cool.jazz|dixieland|delta|smooth.jazz|acid.jazz|nu.jazz)\b/i],
  ['Classical',          /\b(classical|orchestral|opera|chamber|symphony|baroque|contempor|neoclassic|minimali(st)?|modern.classical)\b/i],
  ['Folk & Country',     /\b(folk|country|bluegrass|acoustic(?!.rock)|singer.?songwriter|americana|celtic|irish|western|cowboy|outlaw|appalachian)\b/i],
  ['World & Reggae',     /\b(world|reggae|latin(?!.jazz)|african|caribbean|cuban|salsa|bossa.nova|afrobeat|cumbia|flamenco|tango|polka|turkish|arabic|indian|bollywood|samba|merengue|calypso|afrobeats|dancehall)\b/i],
  ['Gospel & Christian', /\b(gospel|christian|worship|spiritual|hymn|ccm|praise|inspirational|devotional)\b/i],
];
function classifyGenre(name) {
  for (const [label, re] of GENRE_BUCKETS) { if (re.test(name)) return label; }
  return 'Other';
}

// Build genre sections HTML from server-provided groups (or fall back to GENRE_BUCKETS)
// genreGroups: [{name, genres:[{genre,cnt}]}] or null
// allGenres:   [{genre,cnt}]
function _buildGenreSections(genreGroups, allGenres) {
  let sectionList;
  if (genreGroups?.length > 0) {
    sectionList = genreGroups;
  } else {
    // Fall back to GENRE_BUCKETS classifier
    const bucketOrder = [...GENRE_BUCKETS.map(([l]) => l), 'Other'];
    const grouped = {};
    for (const g of allGenres) {
      const cat = classifyGenre(g.genre);
      (grouped[cat] = grouped[cat] || []).push(g);
    }
    sectionList = bucketOrder.filter(cat => grouped[cat]).map(cat => ({ name: cat, genres: grouped[cat] }));
  }
  return sectionList.map(grp => {
    const chips = grp.genres.map(g =>
      `<button class="genre-chip" data-genre="${esc(g.genre)}">${esc(g.genre)}<span class="genre-cnt">${g.cnt}</span></button>`
    ).join('');
    return `<div class="genre-section"><button class="genre-section-head"><span class="genre-section-name">${esc(grp.name)}</span><span class="genre-section-count">${grp.genres.length}</span><svg class="genre-section-chevron" width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="6,9 12,15 18,9"/></svg></button><div class="genre-grid">${chips}</div></div>`;
  }).join('');
}

async function viewGenres() {
  setTitle(t('player.title.genres')); setBack(null); setNavActive('genres'); S.view = 'genres';
  S.curSongs = [];
  document.getElementById('play-all-btn').onclick = null;
  document.getElementById('add-all-btn').onclick  = null;
  setBody('<div class="loading-state"></div>');
  try {
    const d = await api('GET', 'api/v1/db/genre-groups');
    const allGenres = d.genres || [];
    if (!allGenres.length) {
      setBody('<div class="info-panel"><h2>No Genres</h2><p class="info-hint">Your library has no genre tags. Tag your files to use this view.</p></div>');
      return;
    }
    setBody(`<div class="genre-sections">${_buildGenreSections(d.groups, allGenres)}</div>`);
    document.querySelectorAll('.genre-section-head').forEach(btn =>
      btn.addEventListener('click', () => btn.closest('.genre-section').classList.toggle('collapsed'))
    );
    document.querySelectorAll('.genre-chip').forEach(el =>
      el.addEventListener('click', () => viewGenreDetail(el.dataset.genre))
    );
  } catch(e) { setBody('<div class="info-panel"><p class="info-hint">Failed to load genres.</p></div>'); }
}

