// Sync play/pause icon state from audioEl.paused — call this any time the
// Sync play/pause icon state from audioEl.paused — call this any time the
// icon may be stale (restore, logout, etc.) rather than relying on events.
function syncPlayIcons() {
  const playing = !audioEl.paused;
  document.getElementById('icon-play').classList.toggle('hidden',  playing);
  document.getElementById('icon-pause').classList.toggle('hidden', !playing);
  document.getElementById('np-icon-play').classList.toggle('hidden',  playing);
  document.getElementById('np-icon-pause').classList.toggle('hidden', !playing);
  _syncQueueLabel();
}

function _syncQueueLabel() {
  const label = document.getElementById('qp-np-label');
  if (!label) return;
  const hasSong = !!S.queue[S.idx];
  const playing = !audioEl.paused;
  let icon, text;
  if (_xfadeFired) {
    icon = '<svg width="12" height="10" viewBox="0 0 28 24" fill="currentColor"><polygon points="1,3 11,12 1,21" opacity=".55"/><polygon points="9,3 19,12 9,21" opacity=".78"/><polygon points="17,3 27,12 17,21"/></svg>';
    text = t('player.player.crossfading');
  } else if (!hasSong) {
    icon = '<svg width="10" height="10" viewBox="0 0 24 24" fill="currentColor"><rect x="5" y="5" width="14" height="14" rx="1.5"/></svg>';
    text = t('player.player.stopped');
  } else if (!playing) {
    icon = '<svg width="10" height="10" viewBox="0 0 24 24" fill="currentColor"><rect x="5" y="4" width="4" height="16" rx="1.5"/><rect x="15" y="4" width="4" height="16" rx="1.5"/></svg>';
    text = t('player.player.paused');
  } else {
    icon = '<svg width="10" height="10" viewBox="0 0 24 24" fill="currentColor"><polygon points="5,3 19,12 5,21"/></svg>';
    text = t('player.player.nowPlaying');
  }
  const cur = S.queue[S.idx];
  // BPM / Harmonic mixing status chips — shown when Auto-DJ is on and
  // at least one mixing feature is enabled. Each chip has two states:
  //   active  (dj-mx-active) = feature ON + current song has the data → actually filtering
  //   passive (no class)     = feature ON but current song has no BPM/key data → not filtering
  let mxChips = '';
  if (!cur?.isRadio && S.autoDJ) {
    if (S.djBpmContinuity) {
      const refBpm = S.djBpmBase ?? _bpmAnchor ?? _currentBpm;
      const active = refBpm != null;
      const _baseTag = S.djBpmBase != null ? 'base\u202f' : '';
      const label  = active ? `BPM\u202f${_baseTag}${refBpm}\u202f\u00b1${S.djBpmTolerance}` : 'BPM \u2013';
      mxChips += `<span class="dj-mx-chip${active ? ' dj-mx-active' : ''}">${label}</span>`;
    }
    if (S.djHarmonicMixing) {
      const refCamelot = _camelotAnchor ?? _currentCamelot;
      const active = refCamelot != null;
      const label  = active ? `\u266a\u202f${refCamelot}` : '\u266a\u202f\u2013';
      mxChips += `<span class="dj-mx-chip${active ? ' dj-mx-active' : ''}">${label}</span>`;
    }
  }
  const djSub = (!cur?.isRadio && S.autoDJ)
    ? (S.djSimilar
      ? ` <span class="ql-sub-label">· ${t('player.player.djSimilarCrossfade', { cf: S.crossfade > 0 ? ' \u0026 ' + t('player.player.crossfadeShort') : '' })}${mxChips}</span>`
      : ` <span class="ql-sub-label">· ${t('player.player.djActive', { cf: S.crossfade > 0 ? ' \u0026 ' + t('player.player.crossfadeShort') : '' })}${mxChips}</span>`)
    : '';
  // Context sub-label — derived from current song flags or stored playSource
  let ctxSub = '';
  if (!djSub) {
    if (cur?.isRadio) {
      ctxSub = ` <span class="ql-sub-label">· ${t('player.player.radioStream')}</span>`;
    } else if (cur?.isPodcast) {
      const pname = S.playSource?.type === 'podcast' ? S.playSource.name : '';
      ctxSub = ` <span class="ql-sub-label">· ${t('player.player.podcast', { name: pname ? ': ' + esc(pname) : '' })}</span>`;
    } else if (S.playSource?.type === 'playlist') {
      ctxSub = ` <span class="ql-sub-label">· ${t('player.player.playlist', { name: esc(S.playSource.name) })}</span>`;
    } else if (S.playSource?.type === 'smart-playlist') {
      ctxSub = ` <span class="ql-sub-label">· ${t('player.player.smartPlaylist', { name: esc(S.playSource.name) })}</span>`;
    }
  }
  label.innerHTML = icon + ' ' + text + djSub + ctxSub;
}

// ── Tab favicon + dynamic title ──────────────────────────────────────────────
// Playing  → album art drawn to canvas once (no loop)
// Paused / idle → Velvet logo SVG (dark bg + purple m)
const _TabFav = (() => {
  let _icos = null, _song = null, _playing = false, _lastArtSrc = '';
  const _origHrefs = new Map();

  // Velvet idle/paused logo: inline SVG of the neon V — works as a data:image/svg+xml favicon
  const _SVG_VELVET = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 32 32"><defs><linearGradient id="lvg" x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" stop-color="#ff1293"/><stop offset="50%" stop-color="#9d1ae6"/><stop offset="100%" stop-color="#380bb0"/></linearGradient><linearGradient id="rvg" x1="0%" y1="100%" x2="100%" y2="0%"><stop offset="0%" stop-color="#380bb0"/><stop offset="50%" stop-color="#195ee6"/><stop offset="100%" stop-color="#00a2ff"/></linearGradient></defs><path d="M2.5 8C6.4 7.7 13 12.2 16 26c-1.9-2-7.8-10.2-13.5-18z" fill="url(#lvg)"/><path d="M29.5 8C25.6 7.7 19 12.2 16 26c1.9-2 7.8-10.2 13.5-18z" fill="url(#rvg)"/></svg>`;

  function _svgHref(svg) { return 'data:image/svg+xml,' + encodeURIComponent(svg); }
  const _VELVET_HREF = _svgHref(_SVG_VELVET);

  function _init() {
    if (_icos) return;
    _icos = Array.from(document.querySelectorAll('link[rel*="icon"]'))
                 .filter(el => !el.rel.includes('apple'));
    _icos.forEach(el => _origHrefs.set(el, el.href));
  }

  function _setAll(href) { _icos.forEach(el => { el.href = href; }); }

  function _title() {
    if (!_song) { document.title = 'Velvet'; return; }
    const a = _song.artist || '', t = _song.title || (_song.filepath || '').split('/').pop() || '';
    const mark = _playing ? '\u25B6' : '\u23F8';
    document.title = (a && t) ? `${mark} ${a} \u2014 ${t}` : `${mark} ${t || 'Velvet'}`;
  }

  function _drawArt(src) {
    if (!src) { _setAll(_VELVET_HREF); return; }
    if (src === _lastArtSrc) return; // same art, already set
    _lastArtSrc = src;
    const cvs = document.createElement('canvas');
    cvs.width = cvs.height = 32;
    const ctx = cvs.getContext('2d');
    const img = new Image();
    img.crossOrigin = 'anonymous';
    img.onload = () => {
      ctx.save();
      ctx.beginPath();
      if (ctx.roundRect) ctx.roundRect(0, 0, 32, 32, 4); else ctx.rect(0, 0, 32, 32);
      ctx.clip();
      ctx.drawImage(img, 0, 0, 32, 32);
      ctx.restore();
      _setAll(cvs.toDataURL('image/png'));
    };
    img.onerror = () => { _setAll(_VELVET_HREF); };
    img.src = src;
  }

  return {
    setSong(song, playing) {
      _init(); _song = song;
      if (playing !== undefined) _playing = playing;
      _title();
      if (_playing && song) _drawArt(artUrl(song['album-art'], 's'));
      else _setAll(_VELVET_HREF);
    },
    play() {
      _init(); _playing = true; _title();
      if (_song) _drawArt(artUrl(_song['album-art'], 's'));
    },
    pause() { _init(); _playing = false; _lastArtSrc = ''; _title(); _setAll(_VELVET_HREF); },
    reset() { _init(); _song = null; _playing = false; _lastArtSrc = ''; document.title = 'Velvet'; _setAll(_VELVET_HREF); },
  };
})();

// ── AUDIO EVENT HANDLERS (named so they can be moved to a swapped element) ──
function _onAudioPlay()  {
  // Boot guard: block ALL play() calls until the boot overlay has dismissed.
  // This covers every code path — restoreQueue, media session, network recovery,
  // or anything else — so a page refresh NEVER starts playing automatically.
  if (_BOOT_DBG) {
    console.warn('[BOOT] _onAudioPlay: _bootComplete=' + _bootComplete + ' t=' + audioEl.currentTime.toFixed(2) + ' paused=' + audioEl.paused + ' readyState=' + audioEl.readyState + ' playingKey=' + (S.username ? localStorage.getItem(_playingKey()) : 'n/a') + ' sinceBootDismissMs=' + (_bootDismissAt ? Date.now() - _bootDismissAt : 'n/a') + ' audioCtx=' + (audioCtx ? audioCtx.state : 'null') + ' graphBuilt=' + _audioGraphBuilt + ' muted=' + audioEl.muted + ' vol=' + audioEl.volume + ' sinkId=' + (audioEl.sinkId || '') + ' outDev=' + (S.outputDeviceId || '') + ' castMute=' + (_castMuteGain ? _castMuteGain.gain.value : 'n/a') + ' castSonos=' + S.castingToSonos + ' castMpv=' + S.castingToMpv);
    console.warn('[BOOT] _onAudioPlay call stack:', new Error().stack);
  }
  if (!_bootComplete) {
    if (_BOOT_DBG) console.warn('[BOOT] _onAudioPlay: BLOCKED by boot guard — calling pause()');
    audioEl.pause();
    return;
  }
  // Post-boot safety net: within 1500 ms of _bootDismiss, if the saved playing
  // state was paused (playingKey='0') and we have NOT recorded a user gesture,
  // reject this autoplay. Catches late code paths (network-recovery timers,
  // seeked-listeners, bfcache resume) that fire just after _bootComplete=true.
  if (_bootDismissAt && (Date.now() - _bootDismissAt) < 1500 &&
      S.username && localStorage.getItem(_playingKey()) === '0' &&
      (!_lastUserGestureAt || (Date.now() - _lastUserGestureAt) > 2000)) {
    if (_BOOT_DBG) console.warn('[BOOT] _onAudioPlay: BLOCKED by post-boot autoplay guard (playingKey=0, no recent user gesture)');
    audioEl.pause();
    return;
  }
  if (S.username) localStorage.setItem(_playingKey(), '1');
  syncPlayIcons(); VIZ.initAudio(); VU_NEEDLE.start(); _startWaveformRaf(); document.body.classList.add('audio-playing'); _TabFav.play(); _startPositionSync(); if (S.queue[S.idx]?.isRadio) { _radioPlayStart = Date.now(); if (_radioNowPlayingStation) _pollRadioNowPlaying(_radioNowPlayingStation); } if ('mediaSession' in navigator) try { navigator.mediaSession.playbackState = 'playing'; } catch(_e) {} /* Re-apply book speed — browsers reset playbackRate to 1 after audioEl.load() */ if (_isAudioBookSong(S.queue[S.idx]) && S.bookSpeed && S.bookSpeed !== 1) audioEl.playbackRate = S.bookSpeed;
}
function _onAudioPause() { if (S.username) localStorage.setItem(_playingKey(), '0'); syncPlayIcons(); VU_NEEDLE.stop();  _stopWaveformRaf(); document.body.classList.remove('audio-playing'); _TabFav.pause(); _stopPositionSync(); if ('mediaSession' in navigator) try { navigator.mediaSession.playbackState = 'paused';  } catch(_e) {} persistQueue(); /* flush playing:false to localStorage immediately */ _syncQueueToDbNow(false); /* immediate DB write — no debounce — so even a quick clear+refresh sees playing:false */ const _ps = S.queue[S.idx]; if (_isAudioBookSong(_ps) && audioEl.currentTime > 2) { _saveBookPosition(_ps.filepath, audioEl.currentTime); } }
function _onAudioEnded() {
  // Radio stream ended unexpectedly — try to reconnect on the same link
  const _curSong = S.queue[S.idx];
  if (_curSong?.isRadio) {
    setTimeout(() => {
      if (S.queue[S.idx]?.isRadio) {
        audioEl.src = mediaUrl(_curSong._radioLinks[_curSong._radioLinkIdx || 0]);
        audioEl.load(); audioEl.play().catch(() => {});
      }
    }, 3000);
    return;
  }
  if (S.sleepMins === -1) {
    S.sleepMins = 0;
    S.sleepEndsAt = 0;
    _updateSleepLight();
    _showInfoStrip('', '<span class="dj-strip-label">💤 Sleep — playback stopped</span>', 6000, true);
    return;
  }
  // Crossfade: _xfadeEl is already playing through Web Audio.
  // Swap it into the audioEl role — zero gap.
  if (_xfadeFired) {
    _doXfadeHandoff(_xfadeNextIdx);
    return;
  }
  _stopWaveformRaf();
  // Clear saved book position when the audiobook finishes naturally
  if (_isAudioBookSong(_curSong) && _curSong.filepath) {
    _clearBookPosition(_curSong.filepath);
  }
  // Wrapped: fire play-end (natural completion)
  _wrappedEndedNaturally = true;
  if (_wrappedEventId) {
    const eid = _wrappedEventId;
    _wrappedEventId = null;
    api('POST', 'api/v1/wrapped/play-end', {
      eventId:  eid,
      playedMs: Math.max(0, Math.round(((audioEl.duration || 0) - _wrappedTrackStartOffset) * 1000)),
    }).catch(() => {});
  }
  if (_wrappedPodcastEventId) {
    const eid = _wrappedPodcastEventId; _wrappedPodcastEventId = null;
    api('POST', 'api/v1/wrapped/podcast-end', {
      eventId: eid, playedMs: Math.round((audioEl.duration || 0) * 1000), completed: true,
    }).catch(() => {});
  }
  Player.next();
}
// Tracks how many reload attempts have been made for a given src URL so we
// know when to give up and skip rather than loop forever.
const _mediaParseRetries = new Map();
// Filepaths (not URLs) that have previously failed with a parse/demuxer error.
// Used to cache-bust the media URL on the next play attempt so Chrome doesn't
// serve a stale broken stream from its internal media cache.
const _parseErrFilepaths = new Set();

function _onAudioError() {
  if (_sinkSwitching) return;  // suppress errors during audio output device switch
  const err = audioEl.error;
  if (!err || !audioEl.src) return;
  console.warn(`Audio error code ${err.code}: ${err.message || '(no message)'}`);

  // Radio stream error — try next fallback link, or retry from start after delay
  const _radioSong = S.queue[S.idx];
  if (_radioSong?.isRadio) {
    const nextIdx = (_radioSong._radioLinkIdx || 0) + 1;
    if (nextIdx < _radioSong._radioLinks.length) {
      _radioSong._radioLinkIdx = nextIdx;
      audioEl.src = mediaUrl(_radioSong._radioLinks[nextIdx]); // must go through proxy
      audioEl.load(); audioEl.play().catch(() => {});
      toast(`Radio: trying fallback link ${nextIdx + 1}…`);
    } else {
      // All links exhausted (e.g. server restarting) — reset to link 0 and retry after a delay
      _radioSong._radioLinkIdx = 0;
      toast(`⚠ Radio stream unavailable — retrying in 10s…`);
      setTimeout(() => {
        if (S.queue[S.idx] === _radioSong) {
          audioEl.src = mediaUrl(_radioSong._radioLinks[0]);
          audioEl.load(); audioEl.play().catch(() => {});
        }
      }, 10000);
    }
    return;
  }

  // Code 2 = MEDIA_ERR_NETWORK — connection dropped mid-stream; reload.
  if (err.code === MediaError.MEDIA_ERR_NETWORK) {
    _reloadFromPosition(0);
    return;
  }

  // Code 3 = MEDIA_ERR_DECODE, Code 4 = MEDIA_ERR_SRC_NOT_SUPPORTED
  // — the file exists but the browser can't parse it (corrupt, unsupported
  //   codec, bad PTS timestamps, ERR_CONTENT_LENGTH_MISMATCH, etc.).
  // Before retrying, check for a 401 — an expired/missing token produces
  // MEDIA_ERR_SRC_NOT_SUPPORTED and would waste the one retry attempt.
  if (err.code === MediaError.MEDIA_ERR_DECODE ||
      err.code === MediaError.MEDIA_ERR_SRC_NOT_SUPPORTED) {
    const _authSrc = audioEl.src;
    if (_authSrc?.includes('token=')) {
      fetch(_authSrc, { method: 'HEAD' }).then(r => {
        if (r.status === 401 || r.status === 403) {
          S.token = ''; localStorage.removeItem('ms2_token');
          toast(t('player.toast.sessionExpiredReload'));
          setTimeout(() => location.reload(), 2500);
        }
      }).catch(() => {});
    }
    const src = audioEl.src;
    const attempts = _mediaParseRetries.get(src) || 0;
    if (attempts < 1) {
      _mediaParseRetries.set(src, attempts + 1);
      console.warn(`Audio parse error — reload attempt ${attempts + 1}/1 for: ${src}`);
      _reloadFromPosition(0);
      return;
    }
    // Already retried — give up and skip.
    _mediaParseRetries.delete(src);
    const song = S.queue[S.idx];
    const name = song ? (song.title || song.filepath.split('/').pop()) : 'Unknown';
    if (song?.filepath) {
      // Remember this filepath so the next play attempt gets a cache-busted URL
      _parseErrFilepaths.add(song.filepath);
      // Report to Scan Error Workshop so an admin can remux it with ffmpeg
      api('POST', 'api/v1/db/scan-errors/report-playback', {
        filepath: song.filepath,
        errorMsg: (err?.message || '').slice(0, 512),
      }).catch(() => {});
      toast(t('player.toast.parseErrorReported', { name }));
    } else {
      toast(`⚠ Skipping unplayable file: ${name}`);
    }
    Player.next();
    return;
  }
}
function _onAudioStalled() {
  // readyState=0 means no bytes received yet — this is the normal initial-load state
  // when the server is slow to respond. Calling audioEl.load() here would cancel the
  // in-flight HTTP request and restart it, creating a retry loop that multiplies the
  // load time. The error event covers genuine server-unreachable failures.
  if (_BOOT_DBG) console.warn('[BOOT] _onAudioStalled: readyState=' + audioEl.readyState + ' _bootComplete=' + _bootComplete + ' src=...' + audioEl.src.slice(-50));
  if (audioEl.readyState === 0) { return; }
  // Radio streams fire 'stalled'/'waiting' during normal buffering — never seek
  // them back to 0, that would restart the live stream and replay buffered audio.
  if (S.queue[S.idx]?.isRadio) { return; }
  clearTimeout(_netRecoveryTimer);
  _netRecoveryTimer = setTimeout(() => {
    if (audioEl.readyState < 3) {
      console.warn(`Stream stalled (readyState=${audioEl.readyState}) — recovering`);
      _reloadFromPosition(0);
    }
  }, 5000);
}
function _onAudioPlaying()  {
  clearTimeout(_netRecoveryTimer);
  // Only reset the parse-retry counter once we've played enough to know the
  // file is genuinely working. Playing briefly from position 0 while the
  // recovery logic seeks to the resume position would otherwise clear the
  // counter and turn a 1-retry limit into an infinite loop.
  const src = audioEl.src;
  const _clearRetryTimer = setTimeout(() => {
    if (audioEl.src === src && !audioEl.paused) {
      _mediaParseRetries.delete(src);
      // Successfully played — remove from the parse-error set so future plays don't
      // keep adding an unnecessary cache-buster after the file has been fixed.
      const song = S.queue[S.idx];
      if (song?.filepath) _parseErrFilepaths.delete(song.filepath);
    }
  }, 3000);
  audioEl.addEventListener('pause',  () => clearTimeout(_clearRetryTimer), { once: true });
  audioEl.addEventListener('ended',  () => clearTimeout(_clearRetryTimer), { once: true });
  audioEl.addEventListener('error',  () => clearTimeout(_clearRetryTimer), { once: true });
}
function _onAudioCanPlay() { clearTimeout(_netRecoveryTimer); }

// ── CUE SHEET MARKERS ────────────────────────────────────────
async function loadCuePoints(filepath) {
  _cuePoints = [];
  _cueMarkersRendered = false;
  ['cue-markers','np-cue-markers'].forEach(id => { const el = document.getElementById(id); if (el) el.innerHTML = ''; });
  try {
    const fp = encodeURIComponent(filepath);
    const data = await api('GET', `api/v1/db/cuepoints?fp=${fp}`);
    const all = data.cuepoints || [];
    _cueTrack1Title = all.find(cp => cp.t === 0)?.title || '';
    _cuePoints = all.filter(cp => cp.t > 0);
  } catch (_e) { _cuePoints = []; _cueTrack1Title = ''; }
  renderCueMarkers();
  // Update chapter nav button visibility now that cuepoints are known
  _updateAudioBookMode();
}
function renderCueMarkers() {
  if (_cueMarkersRendered || !_cuePoints.length || !audioEl.duration) return;
  _cueMarkersRendered = true;
  const dur = audioEl.duration;
  const html = _cuePoints.map(cp => {
    const pct = (cp.t / dur) * 100;
    if (pct <= 0 || pct >= 100) return '';
    const label = cp.title ? `${cp.no}. ${cp.title}` : `Track ${cp.no}`;
    return `<span class="cue-tick" style="left:${pct.toFixed(2)}%" data-label="${esc(label)}"></span>`;
  }).join('');
  ['cue-markers','np-cue-markers'].forEach(id => {
    const el = document.getElementById(id);
    if (!el) return;
    el.innerHTML = html;
    el.querySelectorAll('.cue-tick').forEach(tick => {
      tick.addEventListener('click', e => {
        e.stopPropagation();
        const dur = Number.isFinite(audioEl.duration) && audioEl.duration > 0 ? audioEl.duration : (S.queue[S.idx]?.duration || 0);
        if (dur > 0) _seekCurrentTrack((Number.parseFloat(tick.style.left) / 100) * dur);
      });
    });
  });
  _updateAudioBookChapterBar();
}

// ── AUDIOBOOK MODE ────────────────────────────────────────────────────────────
// Per-book positions stored as a JSON map in localStorage:
//   key: ms2_book_positions_{username}
//   value: { [filepath]: { t: seconds, savedAt: ms } }
// Capped at 200 entries; old ones are evicted by savedAt.
const AB_POS_LIMIT = 200;
function _abPosKey() { return `ms2_book_positions_${S.username}`; }
function _saveBookPosition(filepath, t) {
  if (!S.username || !filepath || t < 2) return;
  try {
    const raw = localStorage.getItem(_abPosKey());
    const map = raw ? JSON.parse(raw) : {};
    map[filepath] = { t, savedAt: Date.now() };
    // Evict oldest if over limit
    const keys = Object.keys(map);
    if (keys.length > AB_POS_LIMIT) {
      keys.sort((a, b) => (map[a].savedAt || 0) - (map[b].savedAt || 0));
      for (let i = 0; i < keys.length - AB_POS_LIMIT; i++) delete map[keys[i]];
    }
    localStorage.setItem(_abPosKey(), JSON.stringify(map));
  } catch (_e) {}
}
function _loadBookPosition(filepath) {
  if (!S.username || !filepath) return 0;
  try {
    const raw = localStorage.getItem(_abPosKey());
    if (!raw) return 0;
    const map = JSON.parse(raw);
    return map[filepath]?.t || 0;
  } catch (_e) { return 0; }
}
function _clearBookPosition(filepath) {
  if (!S.username || !filepath) return;
  try {
    const raw = localStorage.getItem(_abPosKey());
    if (!raw) return;
    const map = JSON.parse(raw);
    delete map[filepath];
    localStorage.setItem(_abPosKey(), JSON.stringify(map));
  } catch (_e) {}
}

// Update chapter/track indicator (lives inside .bal-row, same height as L/slider/R).
// _cuePoints only contains entries with t>0 (track 1 at t=0 is filtered out),
// so total tracks = _cuePoints.length + 1 and trackNum = boundaries passed + 1.
function _updateAudioBookChapterBar() {
  const bar = document.getElementById('ab-chapter-bar');
  if (!bar) return;
  if (!_cuePoints.length || !audioEl.duration) {
    bar.classList.add('hidden');
    bar.textContent = '';
    return;
  }
  const pos = audioEl.currentTime;
  const total = _cuePoints.length + 1;                      // track 1 at t=0 was filtered
  const passed = _cuePoints.filter(cp => cp.t <= pos);      // boundaries we've crossed
  const trackNum = passed.length + 1;                       // 1-based current track
  const cur = passed[passed.length - 1] || null;            // last boundary crossed (null = track 1)
  const title = cur?.title || (trackNum === 1 ? _cueTrack1Title : '');
  const _chapKey = _isAudioBookSong(S.queue[S.idx]) ? 'player.audiobook.chapterN' : 'player.audiobook.trackN';
  bar.innerHTML = `<span class="ab-chap-num">${t(_chapKey, { n: trackNum, total })}</span><span class="ab-chap-title">${title ? esc(title) : ''}</span>`;
  bar.classList.remove('hidden');

  // ── NP modal artist image: update when CUE chapter artist changes ──────
  // Chapter titles on VA compilations are "Artist - Track Title".
  // Extract the artist part and refresh the avatar if it changed.
  if (title && document.getElementById('np-modal') && !document.getElementById('np-modal').classList.contains('hidden')) {
    const sep = title.indexOf(' - ');
    const cueArtist = sep > 0 ? title.slice(0, sep).trim() : '';
    if (cueArtist && cueArtist !== _npLastCueArtist) {
      _npLastCueArtist = cueArtist;
      const _fp2 = S.queue[S.idx]?.filepath || S.queue[S.idx]?.title || '';
      const _myKey2 = `${_fp2}:${cueArtist}`;
      _npArtistKey = _myKey2;
      api('GET', `api/v1/artists/image?artist=${encodeURIComponent(cueArtist)}`)
        .then(d => {
          if (_npArtistKey !== _myKey2) return; // chapter changed again or song changed
          const wrap = document.getElementById('np-artist-img-wrap');
          if (!wrap) return;
          const s2 = S.queue[S.idx];
          const imgSrc2 = d?.imageFile
            ? `api/v1/artists/images/${encodeURIComponent(d.imageFile)}`
            : artUrl(s2?.['album-art'], 's');
          if (imgSrc2) {
            wrap.innerHTML = `<img src="${imgSrc2}" alt="" loading="eager" onerror="this.parentNode.classList.add('hidden')">`;
            wrap.classList.remove('hidden');
          } else {
            wrap.classList.add('hidden');
            wrap.innerHTML = '';
          }
        })
        .catch(() => {});
    }
  }
  // ── Playing Now view artist image: same CUE chapter logic ─────────────
  if (title && S.view === 'playing-now') {
    const sep2 = title.indexOf(' - ');
    const cueArtist2 = sep2 > 0 ? title.slice(0, sep2).trim() : '';
    if (cueArtist2 && cueArtist2 !== _pnowLastCueArtist) {
      _pnowLastCueArtist = cueArtist2;
      const _fp3 = S.queue[S.idx]?.filepath || '';
      const _key3 = `${_fp3}:${cueArtist2}`;
      api('GET', `api/v1/artists/image?artist=${encodeURIComponent(cueArtist2)}`)
        .then(d => {
          if (_pnowLastCueArtist !== cueArtist2 || _pnowSongFp !== _fp3) return;
          const wrap = document.getElementById('pnow-artist-img-wrap');
          if (!wrap) return;
          const s3 = S.queue[S.idx];
          const src3 = d?.imageFile
            ? `api/v1/artists/images/${encodeURIComponent(d.imageFile)}`
            : artUrl(s3?.['album-art'], 's');
          if (src3) {
            wrap.innerHTML = `<img class="pnow-tadb-img" src="${src3}" alt="" loading="eager" onerror="this.parentNode.style.display='none'">`;
          }
        })
        .catch(() => {});
      // Reload library albums + bio for the new chapter artist (skip image — already updated above)
      _pnowLoadArtistData(cueArtist2, _fp3, true);
    }
  }
}

// Toggle the speed popup.
function _toggleSpeedPop(btn) {
  const pop = document.getElementById('ab-speed-pop');
  if (!pop) return;
  if (!pop.classList.contains('hidden')) { pop.classList.add('hidden'); return; }
  pop.innerHTML = AB_SPEEDS.map(r =>
    `<button class="ab-speed-opt${r === S.bookSpeed ? ' active' : ''}" data-rate="${r}">${r === 1 ? '1×' : r + '×'}</button>`
  ).join('');
  pop.querySelectorAll('.ab-speed-opt').forEach(opt => {
    opt.addEventListener('click', () => {
      const rate = Number.parseFloat(opt.dataset.rate);
      _applyBookSpeed(rate);
      pop.classList.add('hidden');
    });
  });
  // Position above the button
  const rect = btn.getBoundingClientRect();
  pop.style.bottom = (window.innerHeight - rect.top + 6) + 'px';
  pop.style.left   = Math.max(4, rect.left - 10) + 'px';
  pop.classList.remove('hidden');
}

function _applyBookSpeed(rate) {
  S.bookSpeed = rate;
  localStorage.setItem(`ms2_book_speed_${S.username}`, String(rate));
  audioEl.playbackRate = rate;
  const lbl = document.getElementById('ab-speed-label');
  if (lbl) lbl.textContent = rate === 1 ? '1×' : rate + '×';
  // Update active state in open popup
  document.querySelectorAll('.ab-speed-opt').forEach(o => o.classList.toggle('active', Number.parseFloat(o.dataset.rate) === rate));
}

// Show/hide audiobook controls and apply/restore playback speed.
function _updateAudioBookMode() {
  const s = S.queue[S.idx];
  const isBook = _isAudioBookSong(s);
  document.body.classList.toggle('audiobook-mode', isBook);
  // Chapter nav buttons: show for any file with cuepoints (not just audiobook vpath)
  const hasCues = _cuePoints.length >= 2;
  ['ab-prev-chap-btn','ab-next-chap-btn'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.classList.toggle('hidden', !hasCues);
  });
  // Speed button: always visible for audiobooks
  const speedBtn = document.getElementById('ab-speed-btn');
  if (speedBtn) {
    speedBtn.classList.toggle('hidden', !isBook);
    const lbl = document.getElementById('ab-speed-label');
    if (lbl) lbl.textContent = S.bookSpeed === 1 ? '1×' : S.bookSpeed + '×';
  }
  // Apply/restore playback rate
  if (isBook) {
    audioEl.playbackRate = S.bookSpeed;
  } else {
    // Silently reset to 1× for non-audiobook content
    if (audioEl.playbackRate !== 1) audioEl.playbackRate = 1;
  }
  // Chapter bar
  _updateAudioBookChapterBar();
}
function _onAudioTimeupdatePersist() {
  if (_persistTimer) return;
  _persistTimer = setTimeout(() => {
    _persistTimer = null;
    persistQueue();
    // Per-book position save
    const _s = S.queue[S.idx];
    if (_isAudioBookSong(_s) && audioEl.currentTime > 2) {
      _saveBookPosition(_s.filepath, audioEl.currentTime);
    }
  }, 5000);
}
function _onAudioTimeupdateUI() {
  const _cueSong = S.queue[S.idx];
  // CUE virtual track: advance to next queue entry when reaching this track's end boundary
  if (_cueSong?._isCueSplit && _cueSong.cueEndOffset != null &&
      audioEl.currentTime >= _cueSong.cueEndOffset - 0.15) {
    Player.next();
    return;
  }
  // Radio streams: duration is Infinity — show 0:00 left, elapsed right
  if (_cueSong?.isRadio) {
    const elapsed = _radioPlayStart ? Math.floor((Date.now() - _radioPlayStart) / 1000) : 0;
    const elapsedFmt = fmt(elapsed);
    document.getElementById('time-cur').textContent   = '0:00';
    document.getElementById('time-total').textContent = elapsedFmt;
    document.getElementById('np-time-cur').textContent   = '0:00';
    document.getElementById('np-time-total').textContent = elapsedFmt;
    _syncGaplessWaveformNote();
    return;
  }
  if (!audioEl.duration || audioEl.duration === Infinity) {
    _syncGaplessWaveformNote();
    return;
  }
  // Media Session position state — throttled to 1 Hz
  if ('mediaSession' in navigator) {
    const _tNow = Date.now();
    if (_tNow - _msPosThrottle >= 1000) {
      _msPosThrottle = _tNow;
      try { navigator.mediaSession.setPositionState({ duration: audioEl.duration, playbackRate: audioEl.playbackRate, position: audioEl.currentTime }); } catch(_e) {}
    }
  }
  if (_cuePoints.length && !_cueMarkersRendered) renderCueMarkers();
  const _isLiveRadio = !!_cueSong?.isRadio;
  const pct = _isLiveRadio ? 100 : (audioEl.currentTime / audioEl.duration) * 100;
  document.getElementById('prog-fill').style.width = pct + '%';
  const _progThumb = document.getElementById('prog-thumb');
  if (_progThumb) {
    _progThumb.style.display = _isLiveRadio ? 'none' : '';
    if (!_isLiveRadio) _progThumb.style.left = pct + '%';
  }
  _renderTimes();
  // Update track/chapter indicator once per second for any CUE file
  if (_cuePoints.length) {
    const _tNow2 = Date.now();
    if (_tNow2 - (_abChapThrottle || 0) >= 1000) {
      _abChapThrottle = _tNow2;
      _updateAudioBookChapterBar();
    }
  }
  if (S.autoDJ && S.idx === S.queue.length - 1 && _isMusicSong(S.queue[S.idx]) &&
      (audioEl.duration - audioEl.currentTime) < Math.max(
        S.djSimilar ? 45 : 25,   // similar-artists = 2 serial API calls; need more runway
        S.crossfade + 15
      )) {
    autoDJPrefetch();
  }
  if (!document.getElementById('np-modal').classList.contains('hidden')) {
    document.getElementById('np-prog-fill').style.width  = pct + '%';
    _renderTimes();
  }
  VIZ.lyricTick(audioEl.currentTime);
  if (S.crossfade > 0 && !S.gapless && !_xfadeFired && !S.castingToMpv && !S.castingToSonos) {
    if (!S.queue[S.idx]?.isRadio) {
      const remaining = audioEl.duration - audioEl.currentTime;
      if (remaining > 0 && remaining <= S.crossfade) {
        let nextIdx = -1;
        if (S.shuffle) {
          nextIdx = Math.floor(Math.random() * S.queue.length);
        } else if (S.repeat === 'one') {
          nextIdx = S.idx;
        } else if (S.idx < S.queue.length - 1) {
          nextIdx = S.idx + 1;
        } else if (S.repeat === 'all') {
          nextIdx = 0;
        } else if (S.autoDJ && S.queue.length > S.idx + 1) {
          nextIdx = S.idx + 1;
        }
        if (nextIdx !== -1) _startCrossfade(nextIdx);
      }
    }
  }
  // Gapless playback: pre-buffer next track ~8 s before end when crossfade is off.
  // We need the buffer window to be large enough so the browser has time to
  // fetch+decode the start of the next FLAC before audioEl fires 'ended'.
  if (S.gapless && !_xfadeFired && audioEl.duration > 0 && !S.queue[S.idx]?.isRadio) {
    const remaining = audioEl.duration - audioEl.currentTime;
    if (remaining > 0 && remaining <= 8.0) {
      let nextIdx = -1;
      if (S.shuffle)                             nextIdx = Math.floor(Math.random() * S.queue.length);
      else if (S.repeat === 'one')               nextIdx = S.idx;
      else if (S.idx < S.queue.length - 1)       nextIdx = S.idx + 1;
      else if (S.repeat === 'all')               nextIdx = 0;
      else if (S.autoDJ && S.queue.length > S.idx + 1) nextIdx = S.idx + 1;
      if (nextIdx !== -1) _startGapless(nextIdx);
    }
  }
  // Gapless: scheduling is handled by _startGapless setTimeout + Web Audio
  // setValueAtTime — no polling needed here.
  // Waveform scrubber: update shaded fill to reflect playback position
  _updateWaveformProgress();
  _updateSleepLight();
  _syncGaplessWaveformNote();
}

function _onAudioDurationChange() { if (_cuePoints.length && !_cueMarkersRendered) renderCueMarkers(); }
function _attachAudioListeners(el) {
  el.addEventListener('play',           _onAudioPlay);
  el.addEventListener('pause',          _onAudioPause);
  el.addEventListener('ended',          _onAudioEnded);
  el.addEventListener('error',          _onAudioError);
  el.addEventListener('stalled',        _onAudioStalled);
  el.addEventListener('playing',        _onAudioPlaying);
  el.addEventListener('canplay',        _onAudioCanPlay);
  el.addEventListener('timeupdate',     _onAudioTimeupdatePersist);
  el.addEventListener('timeupdate',     _onAudioTimeupdateUI);
  el.addEventListener('seeked',         _onAudioSeeked);
  el.addEventListener('durationchange', _onAudioDurationChange);
  el.addEventListener('loadedmetadata', _onAudioDurationChange);
}
function _detachAudioListeners(el) {
  el.removeEventListener('play',           _onAudioPlay);
  el.removeEventListener('pause',          _onAudioPause);
  el.removeEventListener('ended',          _onAudioEnded);
  el.removeEventListener('error',          _onAudioError);
  el.removeEventListener('stalled',        _onAudioStalled);
  el.removeEventListener('playing',        _onAudioPlaying);
  el.removeEventListener('canplay',        _onAudioCanPlay);
  el.removeEventListener('timeupdate',     _onAudioTimeupdatePersist);
  el.removeEventListener('timeupdate',     _onAudioTimeupdateUI);
  el.removeEventListener('seeked',         _onAudioSeeked);
  el.removeEventListener('durationchange', _onAudioDurationChange);
  el.removeEventListener('loadedmetadata', _onAudioDurationChange);
}

// Sync queue position to DB on user-initiated seek (debounced 1s)
let _seekSyncTimer  = null;
let _mpvSeekTimer   = null;
let _sonosSeekTimer = null;
let _sonosLoadingSong = false; // true for 1 s after a new song is cast to Sonos — suppresses load-triggered seeks
let _sonosSyncFromDevice = false; // true during a device→browser position sync — suppresses Sonos seek echo
let _sonosPollTimer = null;   // interval that syncs browser position from Sonos when casting
let _sonosConsecutiveFailures = 0; // counts consecutive unreachable transport-status responses; auto-deactivates at 3
let _sonosCastTime = 0;       // timestamp of last successful _activateSonosCast — position sync skips corrections during grace period
let _sonosStreamOffset = 0;   // seconds offset for transcoded streams started mid-file: Sonos reports stream-relative position, so add this to convert to original-file position
let _sonosLastRecastAt = 0;   // throttle for the stopped-device self-heal re-cast (resume after the stream drops/idles)

// Start polling Sonos position and syncing audioEl when casting is active.
// When the user seeks in S2/CLIC, Sonos's position drifts from audioEl.currentTime.
// We detect drift >5 s and seek audioEl to match (suppressing the seek echo to Sonos).
function _startSonosPositionSync(ip) {
  if (_sonosPollTimer) clearInterval(_sonosPollTimer);
  _sonosConsecutiveFailures = 0;
  _sonosPollTimer = setInterval(() => {
    if (!S.castingToSonos || !S.sonosRoom) { clearInterval(_sonosPollTimer); _sonosPollTimer = null; return; }
    api('GET', 'api/v1/sonos/transport-status?ip=' + encodeURIComponent(ip))
      .then(st => {
        if (!S.castingToSonos) return;
        // Detect device offline: server returns unreachable:true instead of a real status
        if (st?.unreachable) {
          _sonosConsecutiveFailures++;
          if (_sonosConsecutiveFailures >= 3) {
            // Device has been unreachable for ~9 s — fall back to browser audio automatically
            toast(t('player.output.sonosLost'));
            _deactivateSonosCast(false); // false = skip castStop toast (sonosLost already shown)
          }
          return; // skip position drift correction when device is unreachable
        }
        _sonosConsecutiveFailures = 0; // reset on any successful response
        // Self-heal: device is reachable but STOPPED while we should be playing
        // (the HTTP stream dropped or the device idled). Re-cast the current track
        // at the current position so audio resumes on its own — without the user
        // toggling output Web↔Sonos. Skipped near the natural end of a track so the
        // queue's own 'ended' advance pushes the next song instead.
        const _cur = S.queue[S.idx];
        const _dur = audioEl.duration || _cur?.duration || 0;
        if (st.stopped && S.castingToSonos && _cur && !_cur.isRadio &&
            !audioEl.paused && !_sonosLoadingSong &&
            (Date.now() - _sonosCastTime) >= 8000 &&
            (Date.now() - _sonosLastRecastAt) >= 10000 &&
            _dur > 0 && (audioEl.currentTime || 0) < _dur - 5) {
          _sonosLastRecastAt = Date.now();
          _sonosCastTime = Date.now(); // restart grace so drift-sync doesn't snap the bar to 0 while Sonos re-seeks
          _sonosLoadingSong = true;
          setTimeout(() => { _sonosLoadingSong = false; }, 2500);
          api('POST', 'api/v1/sonos/cast', {
            ip, filepath: _cur.filepath,
            title: _cur.title || '', artist: _cur.artist || '', album: _cur.album || '',
            aaFile: _cur['album-art'] || null,
            seekTo: Math.floor(audioEl.currentTime || 0),
          }).then(r => _handleCastResponse(r)).catch(() => {});
          return; // skip position-drift correction this tick
        }
        const sonosPos = (st.position || 0) + _sonosStreamOffset; // compensate transcoded-stream offset
        const browserPos = audioEl.currentTime || 0;
        // Only sync position when Sonos is actively playing or paused — NOT when
        // stopped/loading (e.g. device has empty queue after page refresh, or is
        // transitioning between tracks). Syncing in stopped state would zero out
        // audioEl.currentTime and cause subsequent re-casts to restart from 0.
        // Also skip for 8 s after a fresh cast: Sonos reports playing+position=0
        // while it is still seeking the HTTP stream internally, which would
        // otherwise reset the visual progress bar to the start of the song.
        const _castGrace = (Date.now() - _sonosCastTime) < 8000;
        if (!_castGrace && (st.playing || st.paused) && Math.abs(sonosPos - browserPos) > 5) {
          _sonosSyncFromDevice = true;
          audioEl.currentTime = sonosPos;
          setTimeout(() => { _sonosSyncFromDevice = false; }, 2000);
        }
      })
      .catch(() => {});
  }, 3000);
}
function _stopSonosPositionSync() {
  clearInterval(_sonosPollTimer);
  _sonosPollTimer = null;
  _sonosConsecutiveFailures = 0;
}

// ── Sonos battery badge ──────────────────────────────────────────────────────
let _sonosBatteryPollTimer = null;

async function _pollSonosBattery() {
  // no-op: badge removed; kept so _startSonosBatteryPoll/_stopSonosBatteryPoll calls are harmless
}

function _startSonosBatteryPoll() {
  _stopSonosBatteryPoll();
}

function _stopSonosBatteryPoll() {
  clearInterval(_sonosBatteryPollTimer);
  _sonosBatteryPollTimer = null;
}
function _onAudioSeeked() {
  persistQueue(); // update localStorage immediately
  clearTimeout(_seekSyncTimer);
  _seekSyncTimer = setTimeout(() => _syncQueueToDb(), 1000);
  // Update track indicator immediately after seek (bypasses 1-Hz throttle)
  if (_cuePoints.length) { _abChapThrottle = 0; _updateAudioBookChapterBar(); }
  // Mirror seek to MPV when casting to server speaker (debounced 400ms to avoid
  // double-firing on initial load seeks)
  if (S.castingToMpv && !_mpvLoadingSong) {
    clearTimeout(_mpvSeekTimer);
    _mpvSeekTimer = setTimeout(() => {
      api('POST', 'api/v1/server-playback/seek', { position: Math.floor(audioEl.currentTime) }).catch(() => {});
    }, 400);
  }
  // Mirror seek to Sonos when casting — skip during initial track load or device-sync seeks
  if (S.castingToSonos && S.sonosRoom && !_sonosLoadingSong && !_sonosSyncFromDevice) {
    clearTimeout(_sonosSeekTimer);
    _sonosSeekTimer = setTimeout(() => {
      api('POST', 'api/v1/sonos/seek', { ip: S.sonosRoom.ip, position: Math.floor(audioEl.currentTime) }).catch(() => {});
    }, 400);
  }
}

// Periodic position-only DB sync every 60 s during playback — keeps the
// position reasonably fresh for cross-device resume without hammering the DB.
let _positionSyncInterval = null;
function _startPositionSync() {
  if (_positionSyncInterval) return;
  _positionSyncInterval = setInterval(() => {
    if (!audioEl.paused && S.token && S.username) {
      persistQueue();
      // Write position directly — skip the debounce so DB is always current
      api('POST', 'api/v1/user/settings', { queue: {
        queue:     S.queue,
        idx:       S.idx,
        time:      audioEl.currentTime || 0,
        playing:   true,
        savedAt:   Date.now(),
        browserId: _browserId,
      }})
        .then(() => localStorage.setItem('ms2_settings_pushed_' + S.username, new Date().toISOString()))
        .catch(() => {});
    }
  }, 60000);
}
function _stopPositionSync() {
  clearInterval(_positionSyncInterval);
  _positionSyncInterval = null;
}

// Attach all permanent listeners to the initial audioEl
_attachAudioListeners(audioEl);

// ── NETWORK RECOVERY (proxy / firewall connection reset) ─────
// Reverse proxies (nginx, Caddy…) reset TCP connections mid-stream when
// their proxy_read_timeout or keepalive limits are hit.  The browser logs
// ERR_CONNECTION_RESET / 206 in the console, continues playing from its
// buffer, then silently pauses when the buffer is exhausted.
//
// Two events signal trouble:
//   • 'error'   – MEDIA_ERR_NETWORK (code 2) once the buffer runs dry
//   • 'stalled' – browser stopped receiving bytes (fires 3 s after the
//                 network goes quiet, BEFORE the buffer actually runs out)
//
// Recovery: capture currentTime, call load() to re-issue the HTTP request,
// then seek back and resume.  If the proxy resets that request too, we retry
// with exponential back-off (max 5 attempts, 1 → 2 → 4 → 8 → 16 s).

let _netRecoveryTimer = null;

function _reloadFromPosition(attempt) {
  attempt = attempt || 0;
  // If the browser is completely offline, don't burn the 5 retry attempts —
  // pause and wait for the 'online' event, then restart recovery from scratch.
  if (!navigator.onLine) {
    clearTimeout(_netRecoveryTimer);
    audioEl.pause();
    toast(t('player.toast.networkOffline'));
    const resume = () => {
      window.removeEventListener('online', resume);
      toast(t('player.toast.networkRestored'));
      _reloadFromPosition(0);
    };
    window.addEventListener('online', resume);
    return;
  }
  if (attempt > 5) {
    console.error('Recovery: gave up after 5 recovery attempts — skipping track');
    const song = S.queue[S.idx];
    const name = song ? (song.title || song.filepath.split('/').pop()) : 'Unknown';
    toast(`⚠ Skipping unreachable file: ${name}`);
    Player.next();
    return;
  }
  // On the very first attempt try to resume from the current position.
  // If that fails (e.g. 416 Range Not Satisfiable after a file rewrite where
  // the new file is smaller), fall back to the start immediately.
  // Starting from 0 is always safe and preferred over an infinite 416 loop.
  const resumeAt = attempt < 1 ? audioEl.currentTime : 0;
  const delay = Math.min(1000 * Math.pow(2, attempt), 30000);
  console.warn(`Recovery attempt ${attempt + 1}/5 — resume from ${Math.round(resumeAt)}s in ${delay}ms`);
  if (_BOOT_DBG) console.warn('[BOOT] _reloadFromPosition: attempt=' + (attempt+1) + ' resumeAt=' + Math.round(resumeAt) + 's _bootComplete=' + _bootComplete);
  clearTimeout(_netRecoveryTimer);
  _netRecoveryTimer = setTimeout(() => {
    audioEl.load(); // re-issues the HTTP GET through the proxy
    const onMeta = () => {
      if (resumeAt > 1) audioEl.currentTime = resumeAt;
      VIZ.initAudio();
      // Only resume if the user was actually playing before the stall.
      // If they had paused (playingKey='0'), do NOT auto-resume — this was
      // the exact cause of autoplay-on-refresh: stall fires during src load
      // in restoreQueue, then recovery plays unconditionally after boot completes.
      const _wasPlaying = S.username ? localStorage.getItem(_playingKey()) === '1' : !audioEl.paused;
      if (_BOOT_DBG) console.warn('[BOOT] _reloadFromPosition onMeta: resumeAt=' + Math.round(resumeAt) + ' _wasPlaying=' + _wasPlaying + ' _bootComplete=' + _bootComplete + ' playingKey=' + localStorage.getItem(_playingKey()));
      if (_wasPlaying) audioEl.play().catch((err) => { if (_BOOT_DBG) console.warn('[BOOT] play() rejected:', err.name, err.message); _reloadFromPosition(attempt + 1); });
    };
    audioEl.addEventListener('loadedmetadata', onMeta, { once: true });
    // If loadedmetadata never fires (proxy keeps resetting), retry
    const retryTimer = setTimeout(() => {
      audioEl.removeEventListener('loadedmetadata', onMeta);
      _reloadFromPosition(attempt + 1);
    }, 12000);
    // Clean up retry timer once we're actually playing
    audioEl.addEventListener('playing', () => clearTimeout(retryTimer), { once: true });
  }, delay);
}

// (error, stalled, playing, canplay, timeupdate × 2 are all registered via _attachAudioListeners above)
// Seek arrow + time bubble on the player-bar progress track
// Arrow is a DOM element: CSS fixes its vertical position, JS only ever sets left.
(function initSeekPreview() {
  const track     = document.getElementById('prog-track');
  const container = track.closest('.player-progress');

  // Triangle arrow — vertical position set in CSS (bottom:7px), never touched by JS
  const arrow = document.createElement('div');
  arrow.className = 'seek-arrow';
  container.appendChild(arrow);

  // Time bubble
  const bubble = document.createElement('div');
  bubble.className = 'seek-preview';
  container.appendChild(bubble);

  function onMove(e) {
    const onCue = e.target.closest('.cue-tick');
    const tRect = track.getBoundingClientRect();
    const cRect = container.getBoundingClientRect();
    const pct   = Math.max(0, Math.min(1, (e.clientX - tRect.left) / tRect.width));
    const xPx   = tRect.left - cRect.left + pct * tRect.width;
    // Only left is set — vertical is governed by CSS alone
    arrow.style.left = xPx + 'px';
    arrow.classList.toggle('sa-cue', !!onCue);
    arrow.classList.add('sa-show');
    if (onCue) { bubble.classList.remove('sp-show'); return; }
    bubble.style.left = xPx + 'px';
    if (audioEl.duration && Number.isFinite(audioEl.duration)) { bubble.textContent = fmt(pct * audioEl.duration); bubble.classList.add('sp-show'); }
  }
  function onLeave() { arrow.classList.remove('sa-show'); bubble.classList.remove('sp-show'); }
  container.addEventListener('mousemove', onMove);
  container.addEventListener('mouseleave', onLeave);
  // Also hide when the song changes (crossfade doesn't trigger mouseleave)
  document.addEventListener('velvet-song-change', onLeave);
  container.addEventListener('click', e => {
    if (e.target.closest('.cue-tick')) return;
    if (S.queue[S.idx]?.isRadio) { _radioSpectrumEnabled = !_radioSpectrumEnabled; _drawWaveform(); return; }
    const r = track.getBoundingClientRect();
    const dur = Number.isFinite(audioEl.duration) && audioEl.duration > 0 ? audioEl.duration : (S.queue[S.idx]?.duration || 0);
    if (dur > 0) _seekCurrentTrack(Math.max(0, Math.min(1, (e.clientX - r.left) / r.width)) * dur);
  });
}());
